# Dark/Light Theme Toggle with Singleton Pattern

Here's a comprehensive, self-contained HTML file with detailed explanations:

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Singleton Theme Manager</title>
  <style>
    /* ============================================================
       CSS CUSTOM PROPERTIES (Design Tokens)
       The Singleton updates these on <html> so every element
       inherits the change automatically — no JS needed per-element.
    ============================================================ */
    :root {
      --bg-primary:    #ffffff;
      --bg-secondary:  #f3f4f6;
      --bg-card:       #ffffff;
      --text-primary:  #111827;
      --text-secondary:#4b5563;
      --text-muted:    #9ca3af;
      --accent:        #6366f1;
      --accent-hover:  #4f46e5;
      --accent-light:  #e0e7ff;
      --border:        #e5e7eb;
      --shadow:        0 1px 3px rgba(0,0,0,.10), 0 1px 2px rgba(0,0,0,.06);
      --shadow-lg:     0 10px 15px rgba(0,0,0,.10), 0 4px 6px rgba(0,0,0,.05);
      --success:       #10b981;
      --warning:       #f59e0b;
      --danger:        #ef4444;
      --code-bg:       #f9fafb;
      --code-border:   #e5e7eb;
      --transition:    .3s cubic-bezier(.4,0,.2,1);
    }

    /* Dark theme tokens — applied by Singleton to html[data-theme="dark"] */
    html[data-theme="dark"] {
      --bg-primary:    #0f172a;
      --bg-secondary:  #1e293b;
      --bg-card:       #1e293b;
      --text-primary:  #f1f5f9;
      --text-secondary:#94a3b8;
      --text-muted:    #64748b;
      --accent:        #818cf8;
      --accent-hover:  #6366f1;
      --accent-light:  #1e1b4b;
      --border:        #334155;
      --shadow:        0 1px 3px rgba(0,0,0,.4),  0 1px 2px rgba(0,0,0,.3);
      --shadow-lg:     0 10px 15px rgba(0,0,0,.4), 0 4px 6px rgba(0,0,0,.3);
      --code-bg:       #0f172a;
      --code-border:   #334155;
    }

    /* ============================================================
       RESET & BASE
    ============================================================ */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    html { scroll-behavior: smooth; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      line-height: 1.6;
      transition: background var(--transition), color var(--transition);
      min-height: 100vh;
    }

    /* ============================================================
       LAYOUT
    ============================================================ */
    .page-wrapper {
      max-width: 900px;
      margin: 0 auto;
      padding: 0 1.25rem 4rem;
    }

    /* ============================================================
       NAVIGATION / HEADER
    ============================================================ */
    .site-nav {
      position: sticky;
      top: 0;
      z-index: 100;
      background: var(--bg-card);
      border-bottom: 1px solid var(--border);
      box-shadow: var(--shadow);
      transition: background var(--transition), border-color var(--transition);
    }

    .nav-inner {
      max-width: 900px;
      margin: 0 auto;
      padding: .75rem 1.25rem;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 1rem;
    }

    .nav-logo {
      font-weight: 700;
      font-size: 1.1rem;
      color: var(--accent);
      text-decoration: none;
      letter-spacing: -.3px;
    }

    .nav-links {
      display: flex;
      gap: 1.5rem;
      list-style: none;
    }

    .nav-links a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: .875rem;
      font-weight: 500;
      transition: color var(--transition);
    }

    .nav-links a:hover { color: var(--accent); }

    /* ---- Theme Toggle Button ---- */
    .theme-toggle {
      display: flex;
      align-items: center;
      gap: .5rem;
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: 9999px;
      padding: .35rem .85rem .35rem .5rem;
      cursor: pointer;
      font-size: .8rem;
      font-weight: 600;
      color: var(--text-secondary);
      transition: background var(--transition), border-color var(--transition),
                  color var(--transition), box-shadow var(--transition);
    }

    .theme-toggle:hover {
      background: var(--accent-light);
      border-color: var(--accent);
      color: var(--accent);
      box-shadow: 0 0 0 3px rgba(99,102,241,.15);
    }

    .theme-toggle:focus-visible {
      outline: 2px solid var(--accent);
      outline-offset: 2px;
    }

    /* Animated pill track */
    .toggle-track {
      width: 36px;
      height: 20px;
      background: var(--text-muted);
      border-radius: 9999px;
      position: relative;
      transition: background var(--transition);
      flex-shrink: 0;
    }

    html[data-theme="dark"] .toggle-track { background: var(--accent); }

    .toggle-thumb {
      position: absolute;
      top: 2px;
      left: 2px;
      width: 16px;
      height: 16px;
      border-radius: 50%;
      background: #fff;
      transition: transform var(--transition);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 9px;
    }

    html[data-theme="dark"] .toggle-thumb { transform: translateX(16px); }

    /* ============================================================
       HERO SECTION
    ============================================================ */
    .hero {
      text-align: center;
      padding: 3.5rem 1rem 2.5rem;
    }

    .hero-badge {
      display: inline-block;
      background: var(--accent-light);
      color: var(--accent);
      font-size: .75rem;
      font-weight: 700;
      letter-spacing: .05em;
      text-transform: uppercase;
      padding: .3rem .8rem;
      border-radius: 9999px;
      margin-bottom: 1rem;
    }

    .hero h1 {
      font-size: clamp(1.75rem, 4vw, 2.75rem);
      font-weight: 800;
      line-height: 1.2;
      letter-spacing: -.5px;
      margin-bottom: .75rem;
    }

    .hero h1 span { color: var(--accent); }

    .hero p {
      color: var(--text-secondary);
      font-size: 1.05rem;
      max-width: 580px;
      margin: 0 auto 1.75rem;
    }

    .hero-actions {
      display: flex;
      gap: .75rem;
      justify-content: center;
      flex-wrap: wrap;
    }

    /* ============================================================
       BUTTONS
    ============================================================ */
    .btn {
      display: inline-flex;
      align-items: center;
      gap: .4rem;
      padding: .6rem 1.25rem;
      border-radius: .5rem;
      font-size: .875rem;
      font-weight: 600;
      cursor: pointer;
      border: none;
      transition: all var(--transition);
      text-decoration: none;
    }

    .btn-primary {
      background: var(--accent);
      color: #fff;
    }

    .btn-primary:hover {
      background: var(--accent-hover);
      box-shadow: var(--shadow-lg);
      transform: translateY(-1px);
    }

    .btn-secondary {
      background: var(--bg-secondary);
      color: var(--text-primary);
      border: 1px solid var(--border);
    }

    .btn-secondary:hover {
      border-color: var(--accent);
      color: var(--accent);
      transform: translateY(-1px);
    }

    /* ============================================================
       SECTION HEADINGS
    ============================================================ */
    .section { margin-top: 3rem; }

    .section-header {
      display: flex;
      align-items: center;
      gap: .75rem;
      margin-bottom: 1.25rem;
    }

    .section-icon {
      width: 36px;
      height: 36px;
      border-radius: .5rem;
      background: var(--accent-light);
      color: var(--accent);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 1rem;
      flex-shrink: 0;
    }

    .section-header h2 {
      font-size: 1.3rem;
      font-weight: 700;
      letter-spacing: -.3px;
    }

    /* ============================================================
       CARDS
    ============================================================ */
    .card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: .75rem;
      padding: 1.5rem;
      box-shadow: var(--shadow);
      transition: background var(--transition), border-color var(--transition),
                  box-shadow var(--transition);
    }

    .card:hover { box-shadow: var(--shadow-lg); }

    .card-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
      gap: 1rem;
    }

    .card h3 {
      font-size: 1rem;
      font-weight: 700;
      margin-bottom: .4rem;
    }

    .card p {
      font-size: .875rem;
      color: var(--text-secondary);
      line-height: 1.55;
    }

    .card-accent-bar {
      height: 3px;
      border-radius: 9999px;
      margin-bottom: 1rem;
    }

    /* ============================================================
       STATUS BADGES
    ============================================================ */
    .badge {
      display: inline-block;
      padding: .2rem .6rem;
      border-radius: 9999px;
      font-size: .7rem;
      font-weight: 700;
      letter-spacing: .04em;
      text-transform: uppercase;
    }

    .badge-success { background: #d1fae5; color: #065f46; }
    .badge-warning { background: #fef3c7; color: #92400e; }
    .badge-danger  { background: #fee2e2; color: #991b1b; }
    .badge-info    { background: var(--accent-light); color: var(--accent); }

    html[data-theme="dark"] .badge-success { background: #064e3b; color: #6ee7b7; }
    html[data-theme="dark"] .badge-warning { background: #451a03; color: #fcd34d; }
    html[data-theme="dark"] .badge-danger  { background: #450a0a; color: #fca5a5; }

    /* ============================================================
       DATA TABLE
    ============================================================ */
    .table-wrapper {
      overflow-x: auto;
      border-radius: .75rem;
      border: 1px solid var(--border);
      box-shadow: var(--shadow);
    }

    table {
      width: 100%;
      border-collapse: collapse;
      font-size: .875rem;
      background: var(--bg-card);
      transition: background var(--transition);
    }

    thead {
      background: var(--bg-secondary);
      transition: background var(--transition);
    }

    th {
      padding: .75rem 1rem;
      text-align: left;
      font-weight: 700;
      font-size: .8rem;
      letter-spacing: .04em;
      text-transform: uppercase;
      color: var(--text-secondary);
      border-bottom: 1px solid var(--border);
    }

    td {
      padding: .75rem 1rem;
      border-bottom: 1px solid var(--border);
      color: var(--text-primary);
      vertical-align: middle;
    }

    tr:last-child td { border-bottom: none; }

    tbody tr {
      transition: background var(--transition);
    }

    tbody tr:hover { background: var(--bg-secondary); }

    /* ============================================================
       CODE BLOCKS
    ============================================================ */
    .code-block {
      background: var(--code-bg);
      border: 1px solid var(--code-border);
      border-radius: .75rem;
      padding: 1.25rem 1.5rem;
      overflow-x: auto;
      font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
      font-size: .82rem;
      line-height: 1.7;
      transition: background var(--transition), border-color var(--transition);
      position: relative;
    }

    .code-block pre { margin: 0; }

    /* Simple syntax colouring that works in both themes */
    .kw  { color: #7c3aed; font-weight: 600; }   /* keyword   */
    .fn  { color: #0369a1; }                       /* function  */
    .str { color: #059669; }                       /* string    */
    .cm  { color: var(--text-muted); font-style: italic; } /* comment */
    .nm  { color: #b45309; }                       /* number    */

    html[data-theme="dark"] .kw  { color: #a78bfa; }
    html[data-theme="dark"] .fn  { color: #38bdf8; }
    html[data-theme="dark"] .str { color: #34d399; }
    html[data-theme="dark"] .nm  { color: #fbbf24; }

    .code-label {
      display: inline-block;
      background: var(--accent);
      color: #fff;
      font-size: .7rem;
      font-weight: 700;
      letter-spacing: .05em;
      text-transform: uppercase;
      padding: .2rem .6rem;
      border-radius: .25rem;
      margin-bottom: .75rem;
    }

    /* ============================================================
       PROS / CONS LIST
    ============================================================ */
    .pros-cons-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1rem;
    }

    @media (max-width: 560px) {
      .pros-cons-grid { grid-template-columns: 1fr; }
      .nav-links { display: none; }
    }

    .pros-card  { border-left: 4px solid var(--success); }
    .cons-card  { border-left: 4px solid var(--danger);  }

    .pros-card h3 { color: var(--success); }
    .cons-card h3 { color: var(--danger);  }

    .check-list {
      list-style: none;
      margin-top: .75rem;
      display: flex;
      flex-direction: column;
      gap: .5rem;
    }

    .check-list li {
      display: flex;
      gap: .6rem;
      font-size: .875rem;
      color: var(--text-secondary);
      line-height: 1.45;
    }

    .check-list li .icon { flex-shrink: 0; margin-top: .1rem; }

    /* ============================================================
       ALERT / CALLOUT
    ============================================================ */
    .callout {
      display: flex;
      gap: .9rem;
      padding: 1rem 1.25rem;
      border-radius: .75rem;
      border: 1px solid;
      margin-top: 1rem;
      font-size: .875rem;
      line-height: 1.55;
    }

    .callout-info {
      background: var(--accent-light);
      border-color: var(--accent);
      color: var(--text-primary);
    }

    .callout-warning {
      background: #fffbeb;
      border-color: var(--warning);
      color: #78350f;
    }

    html[data-theme="dark"] .callout-warning {
      background: #1c1400;
      color: #fde68a;
      border-color: #d97706;
    }

    .callout-icon { font-size: 1.1rem; flex-shrink: 0; margin-top: .05rem; }

    /* ============================================================
       LIVE DEMO COUNTER
    ============================================================ */
    .demo-panel {
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: .75rem;
      padding: 1.5rem;
      display: flex;
      flex-wrap: wrap;
      gap: 1.25rem;
      align-items: center;
      justify-content: space-between;
      transition: background var(--transition), border-color var(--transition);
    }

    .demo-info { flex: 1; min-width: 200px; }
    .demo-info h3 { font-size: 1rem; font-weight: 700; margin-bottom: .25rem; }
    .demo-info p  { font-size: .85rem; color: var(--text-secondary); }

    .demo-stat {
      text-align: center;
      min-width: 90px;
    }

    .demo-stat .number {
      font-size: 2rem;
      font-weight: 800;
      color: var(--accent);
      line-height: 1;
      transition: transform .15s;
    }

    .demo-stat .number.bump { transform: scale(1.3); }

    .demo-stat .label {
      font-size: .7rem;
      text-transform: uppercase;
      letter-spacing: .05em;
      color: var(--text-muted);
      margin-top: .2rem;
    }

    /* ============================================================
       FORM ELEMENTS
    ============================================================ */
    .form-group { margin-bottom: 1rem; }

    label {
      display: block;
      font-size: .8rem;
      font-weight: 600;
      color: var(--text-secondary);
      margin-bottom: .35rem;
      text-transform: uppercase;
      letter-spacing: .04em;
    }

    input[type="text"],
    select,
    textarea {
      width: 100%;
      padding: .6rem .85rem;
      background: var(--bg-primary);
      border: 1px solid var(--border);
      border-radius: .5rem;
      color: var(--text-primary);
      font-size: .875rem;
      font-family: inherit;
      transition: border-color var(--transition), background var(--transition),
                  box-shadow var(--transition);
      outline: none;
    }

    input[type="text"]:focus,
    select:focus,
    textarea:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(99,102,241,.15);
    }

    textarea { resize: vertical; min-height: 80px; }

    /* ============================================================
       PROGRESS BARS
    ============================================================ */
    .progress-row {
      margin-bottom: .85rem;
    }

    .progress-label {
      display: flex;
      justify-content: space-between;
      font-size: .8rem;
      margin-bottom: .3rem;
      color: var(--text-secondary);
    }

    .progress-track {
      height: 8px;
      background: var(--bg-secondary);
      border-radius: 9999px;
      overflow: hidden;
      border: 1px solid var(--border);
    }

    .progress-fill {
      height: 100%;
      border-radius: 9999px;
      transition: width 1s ease;
    }

    /* ============================================================
       FOOTER
    ============================================================ */
    .site-footer {
      margin-top: 4rem;
      padding: 1.5rem 1.25rem;
      border-top: 1px solid var(--border);
      text-align: center;
      font-size: .8rem;
      color: var(--text-muted);
      transition: border-color var(--transition);
    }

    /* ============================================================
       THEME TRANSITION OVERLAY  (brief flash on toggle)
    ============================================================ */
    .theme-flash {
      position: fixed;
      inset: 0;
      pointer-events: none;
      z-index: 9999;
      opacity: 0;
      background: var(--bg-primary);
      transition: opacity .15s ease;
    }

    .theme-flash.active { opacity: .25; }

    /* ============================================================
       SCROLL-REVEAL UTILITY
    ============================================================ */
    .reveal {
      opacity: 0;
      transform: translateY(16px);
      transition: opacity .5s ease, transform .5s ease;
    }

    .reveal.visible {
      opacity: 1;
      transform: none;
    }
  </style>
</head>
<body>

<!-- Flash overlay for smooth theme switch feel -->
<div class="theme-flash" id="themeFlash"></div>

<!-- ============================================================
     NAVIGATION
============================================================ -->
<nav class="site-nav" role="navigation" aria-label="Main navigation">
  <div class="nav-inner">
    <a href="#" class="nav-logo">⬡ SingletonUI</a>
    <ul class="nav-links">
      <li><a href="#pattern">Pattern</a></li>
      <li><a href="#demo">Demo</a></li>
      <li><a href="#tradeoffs">Trade-offs</a></li>
      <li><a href="#alternatives">Alternatives</a></li>
    </ul>
    <button
      class="theme-toggle"
      id="themeToggle"
      aria-label="Toggle colour theme"
      aria-pressed="false"
    >
      <span class="toggle-track" aria-hidden="true">
        <span class="toggle-thumb" id="toggleThumb">☀️</span>
      </span>
      <span id="toggleLabel">Light</span>
    </button>
  </div>
</nav>

<!-- ============================================================
     HERO
============================================================ -->
<div class="page-wrapper">
  <header class="hero reveal">
    <span class="hero-badge">Design Pattern Deep-Dive</span>
    <h1>Theme Management<br>with the <span>Singleton Pattern</span></h1>
    <p>
      A practical, fully-annotated demonstration of how the Singleton pattern
      manages global UI state — and an honest look at when you should reach
      for something else entirely.
    </p>
    <div class="hero-actions">
      <button class="btn btn-primary" onclick="ThemeManager.getInstance().toggle()">
        ✨ Toggle Theme Now
      </button>
      <a href="#pattern" class="btn btn-secondary">📖 Read the Explanation</a>
    </div>
  </header>

  <!-- ============================================================
       SECTION 1 — THE PATTERN ITSELF
  ============================================================ -->
  <section class="section reveal" id="pattern">
    <div class="section-header">
      <div class="section-icon">🏗️</div>
      <h2>The Singleton Implementation</h2>
    </div>

    <div class="card" style="margin-bottom:1rem;">
      <p style="color:var(--text-secondary); font-size:.9rem; margin-bottom:1rem;">
        The Singleton pattern ensures a class has <strong>exactly one instance</strong>
        and provides a global access point to it. Below is the exact code powering
        this page's theme system, with every line explained.
      </p>

      <div class="code-label">JavaScript — ThemeManager Singleton</div>
      <div class="code-block"><pre><code
><span class="cm">/**
 * ThemeManager — Singleton
 *
 * Responsibilities:
 *   1. Hold the single source of truth for the current theme.
 *   2. Persist the user's choice to localStorage.
 *   3. Apply the theme to the DOM via a data-attribute.
 *   4. Notify any registered listeners of changes.
 */</span>
<span class="kw">class</span> <span class="fn">ThemeManager</span> {

  <span class="cm">// ── Private static slot for the one instance ──────────────</span>
  <span class="kw">static</span> #instance = <span class="kw">null</span>;

  <span class="cm">// ── Private state ─────────────────────────────────────────</span>
  #theme       = <span class="str">'light'</span>;
  #listeners   = <span class="kw">new</span> <span class="fn">Set</span>();
  #toggleCount = <span class="nm">0</span>;

  <span class="cm">// ── Private constructor — called ONCE ─────────────────────</span>
  <span class="fn">constructor</span>() {
    <span class="kw">if</span> (<span class="fn">ThemeManager</span>.#instance) {
      <span class="cm">// Guard: throw instead of silently returning the old one.</span>
      <span class="kw">throw new</span> <span class="fn">Error</span>(<span class="str">'Use ThemeManager.getInstance()'</span>);
    }
    <span class="kw">this</span>.<span class="fn">#init</span>();
  }

  <span class="cm">// ── The global access point ───────────────────────────────</span>
  <span class="kw">static</span> <span class="fn">getInstance</span>() {
    <span class="kw">if</span> (!<span class="fn">ThemeManager</span>.#instance) {
      <span class="fn">ThemeManager</span>.#instance = <span class="kw">new</span> <span class="fn">ThemeManager</span>();
    }
    <span class="kw">return</span> <span class="fn">ThemeManager</span>.#instance;
  }

  <span class="cm">// ── Initialise: respect OS preference & saved choice ──────</span>
  <span class="fn">#init</span>() {
    <span class="kw">const</span> saved  = <span class="fn">localStorage</span>.getItem(<span class="str">'theme'</span>);
    <span class="kw">const</span> prefersDark =
      <span class="fn">window</span>.matchMedia(<span class="str">'(prefers-color-scheme: dark)'</span>).matches;

    <span class="kw">this</span>.#theme = saved ?? (prefersDark ? <span class="str">'dark'</span> : <span class="str">'light'</span>);
    <span class="kw">this</span>.<span class="fn">#apply</span>();
  }

  <span class="cm">// ── Write theme to the DOM ────────────────────────────────</span>
  <span class="fn">#apply</span>() {
    <span class="fn">document</span>.documentElement
      .setAttribute(<span class="str">'data-theme'</span>, <span class="kw">this</span>.#theme);
    <span class="fn">localStorage</span>.setItem(<span class="str">'theme'</span>, <span class="kw">this</span>.#theme);
    <span class="kw">this</span>.<span class="fn">#notify</span>();
  }

  <span class="cm">// ── Public API ────────────────────────────────────────────</span>
  <span class="fn">toggle</span>() {
    <span class="kw">this</span>.#theme = <span class="kw">this</span>.#theme === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    <span class="kw">this</span>.#toggleCount++;
    <span class="kw">this</span>.<span class="fn">#apply</span>();
  }

  <span class="fn">setTheme</span>(name) {
    <span class="kw">if</span> (![<span class="str">'light'</span>, <span class="str">'dark'</span>].includes(name)) <span class="kw">return</span>;
    <span class="kw">this</span>.#theme = name;
    <span class="kw">this</span>.<span class="fn">#apply</span>();
  }

  <span class="kw">get</span> <span class="fn">theme</span>()       { <span class="kw">return</span> <span class="kw">this</span>.#theme; }
  <span class="kw">get</span> <span class="fn">isDark</span>()      { <span class="kw">return</span> <span class="kw">this</span>.#theme === <span class="str">'dark'</span>; }
  <span class="kw">get</span> <span class="fn">toggleCount</span>() { <span class="kw">return</span> <span class="kw">this</span>.#toggleCount; }

  <span class="cm">// ── Observer mini-pattern for UI sync ────────────────────</span>
  <span class="fn">subscribe</span>(fn)   { <span class="kw">this</span>.#listeners.add(fn); }
  <span class="fn">unsubscribe</span>(fn) { <span class="kw">this</span>.#listeners.delete(fn); }
  <span class="fn">#notify</span>()       { <span class="kw">this</span>.#listeners.forEach(fn => <span class="fn">fn</span>(<span class="kw">this</span>.#theme)); }
}
</code></pre></div>
    </div>

    <div class="callout callout-info">
      <span class="callout-icon">💡</span>
      <div>
        <strong>Why private class fields (<code>#</code>)?</strong>
        Using <code>#instance</code>, <code>#theme</code>, and <code>#listeners</code>
        means no external code can accidentally mutate internal state.
        The only way in is through the public API — a key principle of
        encapsulation that makes the Singleton safer in practice.
      </div>
    </div>
