><span class="cm">// ✅ Testable — the dependency is explicit and swappable</span>
<span class="kw">function</span> <span class="fn">renderNavbar</span>(themeService) {
  <span class="kw">const</span> btn = <span class="fn">document</span>.querySelector(<span class="str">'#toggle'</span>);
  btn.addEventListener(<span class="str">'click'</span>, () => themeService.<span class="fn">toggle</span>());
