}

<span class="cm">// Production: inject the real manager</span>
<span class="fn">renderNavbar</span>(<span class="fn">ThemeManager</span>.getInstance());

<span class="cm">// Test: inject a mock — no global state pollution!</span>
<span class="fn">renderNavbar</span>({
  <span class="fn">toggle</span>: jest.fn(),
  <span class="fn">subscribe</span>: jest.fn(),
});

<span class="cm">// ❌ Hard to test — hidden coupling to global state</span>
<span class="kw">function</span> <span class="fn">renderNavbarBad</span>() {
  <span class="kw">const</span> tm = <span class="fn">ThemeManager</span>.getInstance(); <span class="cm">// ← surprise dependency</span>
  <span class="cm">// ...</span>
}
</code></pre></div>
