><span class="cm">// ThemeContext.jsx</span>
<span class="kw">const</span> ThemeCtx = <span class="fn">createContext</span>(<span class="kw">null</span>);

<span class="kw">export function</span> <span class="fn">ThemeProvider</span>({ children }) {
  <span class="kw">const</span> [theme, setTheme] = <span class="fn">useState</span>(<span class="str">'light'</span>);
  <span class="kw">const</span> toggle = () => <span class="fn">setTheme</span>(t => t === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>);

  <span class="kw">return</span> (
