  <!-- ============================================================
       SECTION 2 — WHAT IS A SINGLETON?
       ============================================================ -->
  <section class="section" aria-labelledby="what-heading">
    <div class="section-header">
      <span class="section-icon" aria-hidden="true">📖</span>
      <h2 class="section-title" id="what-heading">What Is the Singleton Pattern?</h2>
    </div>
    <p class="section-desc">
      A Singleton is a creational design pattern that restricts a class to a
      <strong>single instance</strong> and provides a global access point to it.
      It was popularised by the Gang of Four (GoF) in their 1994 book
      <em>Design Patterns: Elements of Reusable Object-Oriented Software</em>.
    </p>

    <div class="grid-3">
      <div class="card">
        <span class="card-icon">🔒</span>
        <div class="card-title">Single Instance</div>
        <div class="card-body">
          The constructor is made private (or guarded). A static <code>getInstance()</code>
          method returns the same object every time it is called, no matter how many
          call sites exist.
        </div>
      </div>
      <div class="card">
        <span class="card-icon">🌐</span>
        <div class="card-title">Global Access Point</div>
        <div class="card-body">
          Any module can reach the instance without passing it through function
          arguments or constructors — the instance is effectively a controlled global.
        </div>
      </div>
      <div class="card">
        <span class="card-icon">⚡</span>
        <div class="card-title">Lazy Initialisation</div>
        <div class="card-body">
          The instance is typically created only when first requested, not at
          program start-up, saving resources when the feature may never be used.
        </div>
      </div>
    </div>
  </section>

  <!-- ============================================================
       SECTION 3 — THE CODE
       ============================================================ -->
  <section class="section" id="code" aria-labelledby="code-heading">
    <div class="section-header">
      <span class="section-icon" aria-hidden="true">💻</span>
      <h2 class="section-title" id="code-heading">The ThemeManager Singleton</h2>
    </div>
    <p class="section-desc">
      Below is the exact JavaScript powering this page, annotated line by line.
      It combines the Singleton pattern with the Observer pattern so that multiple
      UI components can react to theme changes without being tightly coupled.
    </p>

    <pre><code><span class="cm">/**
 * ThemeManager — Singleton + Observer
 *
 * Responsibilities:
 *   1. Guarantee only ONE instance ever exists (Singleton).
 *   2. Persist the user's preference to localStorage.
 *   3. Apply the theme by writing a data-attribute on <html>.
 *   4. Notify registered observers whenever the theme changes (Observer).
 */</span>
<span class="kw">class</span> <span class="fn">ThemeManager</span> {

  <span class="cm">// ── Singleton guard ──────────────────────────────────────────</span>
  <span class="cm">// A static field on the CLASS (not the instance) holds the one</span>
  <span class="cm">// and only reference.  null means "not yet created".</span>
  <span class="kw">static</span> #instance = <span class="kw">null</span>;

  <span class="cm">// ── Private state ────────────────────────────────────────────</span>
  #theme     = <span class="str">'light'</span>;   <span class="cm">// current theme string</span>
  #observers = [];        <span class="cm">// list of { id, callback } objects</span>
  #toggleCount = <span class="num">0</span>;      <span class="cm">// how many times the user has toggled</span>
  #notifCount  = <span class="num">0</span>;      <span class="cm">// total observer notifications dispatched</span>

  <span class="cm">// ── Constructor ──────────────────────────────────────────────</span>
  <span class="cm">// Private by convention (JS doesn't enforce private constructors).</span>
  <span class="cm">// We guard it manually: if getInstance() was already called, throw.</span>
  <span class="fn">constructor</span>() {
    <span class="kw">if</span> (<span class="fn">ThemeManager</span>.#instance) {
      <span class="kw">throw new</span> <span class="fn">Error</span>(
        <span class="str">'ThemeManager is a Singleton. Use ThemeManager.getInstance().'</span>
      );
    }
    <span class="cm">// Restore persisted preference, fall back to OS preference,</span>
    <span class="cm">// then fall back to 'light'.</span>
    <span class="kw">const</span> saved = <span class="fn">localStorage</span>.getItem(<span class="str">'theme'</span>);
    <span class="kw">const</span> osPref = <span class="fn">window</span>.matchMedia(<span class="str">'(prefers-color-scheme: dark)'</span>)
                         .matches ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    <span class="kw">this</span>.#theme = saved ?? osPref;
    <span class="kw">this</span>.#applyTheme();
  }

  <span class="cm">// ── Static factory ───────────────────────────────────────────</span>
  <span class="cm">// THIS is the only public way to obtain the manager.</span>
  <span class="cm">// Calling it 100 times returns the exact same object.</span>
  <span class="kw">static</span> <span class="fn">getInstance</span>() {
    <span class="kw">if</span> (!<span class="fn">ThemeManager</span>.#instance) {
      <span class="fn">ThemeManager</span>.#instance = <span class="kw">new</span> <span class="fn">ThemeManager</span>();
    }
    <span class="kw">return</span> <span class="fn">ThemeManager</span>.#instance;
  }

  <span class="cm">// ── Observer registration ────────────────────────────────────</span>
  <span class="fn">subscribe</span>(id, callback) {
    <span class="kw">this</span>.#observers.push({ id, callback });
  }

  <span class="fn">unsubscribe</span>(id) {
    <span class="kw">this</span>.#observers = <span class="kw">this</span>.#observers
      .filter(o => o.id !== id);
  }

  <span class="cm">// ── Theme toggling ───────────────────────────────────────────</span>
  <span class="fn">toggle</span>() {
    <span class="kw">this</span>.#theme = <span class="kw">this</span>.#theme === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    <span class="kw">this</span>.#toggleCount++;
    <span class="kw">this</span>.#applyTheme();
    <span class="kw">this</span>.#notifyObservers();
    <span class="fn">localStorage</span>.setItem(<span class="str">'theme'</span>, <span class="kw">this</span>.#theme);
  }

  <span class="cm">// ── Internal helpers ─────────────────────────────────────────</span>
  #<span class="fn">applyTheme</span>() {
    <span class="cm">// Writing a data-attribute on the root element is the bridge</span>
    <span class="cm">// between JavaScript state and CSS custom properties.</span>
    <span class="fn">document</span>.documentElement.setAttribute(<span class="str">'data-theme'</span>, <span class="kw">this</span>.#theme);
  }

  #<span class="fn">notifyObservers</span>() {
    <span class="kw">const</span> payload = { theme: <span class="kw">this</span>.#theme, count: <span class="kw">this</span>.#toggleCount };
    <span class="kw">this</span>.#observers.<span class="fn">forEach</span>(o => {
      o.<span class="fn">callback</span>(payload);
      <span class="kw">this</span>.#notifCount++;
    });
  }

  <span class="cm">// ── Getters (read-only public surface) ───────────────────────</span>
  <span class="kw">get</span> <span class="fn">theme</span>()         { <span class="kw">return this</span>.#theme;        }
  <span class="kw">get</span> <span class="fn">isDark</span>()        { <span class="kw">return this</span>.#theme === <span class="str">'dark'</span>; }
  <span class="kw">get</span> <span class="fn">toggleCount</span>()   { <span class="kw">return this</span>.#toggleCount;   }
  <span class="kw">get</span> <span class="fn">notifCount</span>()    { <span class="kw">return this</span>.#notifCount;    }
  <span class="kw">get</span> <span class="fn">observerCount</span>() { <span class="kw">return this</span>.#observers.length; }
}
</code></pre>

    <div class="callout callout-tip">
      <div class="callout-title">💡 Why <code>data-theme</code> on <code>&lt;html&gt;</code>?</div>
      <p>
        CSS custom properties cascade from parent to child. By setting the attribute
        on the root element, every single element on the page automatically inherits
        the correct token values — no JavaScript DOM walking required.
        The Singleton writes <em>one attribute</em>; CSS does the rest.
      </p>
    </div>
  </section>

  <hr class="divider" />

  <!-- ============================================================
       SECTION 4 — PROS / CONS
       ============================================================ -->
  <section class="section" id="tradeoffs" aria-labelledby="tradeoffs-heading">
    <div class="section-header">
      <span class="section-icon" aria-hidden="true">⚖️</span>
      <h2 class="section-title" id="tradeoffs-heading">Honest Trade-offs</h2>
    </div>
    <p class="section-desc">
      The Singleton is one of the most recognised — and most criticised — patterns
      in software engineering. Here is an unvarnished look at both sides.
    </p>

    <!-- Pro callouts -->
    <div class="callout callout-pro">
      <div class="callout-title">✅ Pro — Controlled shared state</div>
      <p>
        When genuinely global state is needed (theme, locale, feature flags, a
        connection pool), a Singleton provides a single, auditable place to
        read and write it. Without it, the same state gets duplicated across
        modules and falls out of sync.
      </p>
    </div>

    <div class="callout callout-pro">
      <div class="callout-title">✅ Pro — Lazy initialisation</div>
      <p>
        The instance is created only when first requested. If the feature is
        never used in a given session, no resources are allocated. This is
        especially valuable for expensive resources like database connections.
      </p>
    </div>

    <div class="callout callout-pro">
      <div class="callout-title">✅ Pro — Simple access from anywhere</div>
      <p>
        <code>ThemeManager.getInstance()</code> works from any module without
        import chains or prop-drilling. For cross-cutting concerns that truly
        span the whole application, this convenience is real.
      </p>
    </div>

    <div class="callout callout-con mt-2">
      <div class="callout-title">❌ Con — Hidden dependency / tight coupling</div>
      <p>
        Any function that calls <code>ThemeManager.getInstance()</code> has an
        invisible dependency. You cannot tell from the function signature alone
        that it touches global state. This makes code harder to reason about
        and refactor.
      </p>
    </div>

    <div class="callout callout-con">
      <div class="callout-title">❌ Con — Testing is painful</div>
      <p>
        Unit tests need isolation. A Singleton carries state between tests unless
        you add a <code>resetInstance()</code> escape hatch — which defeats the
        purpose of the pattern. Mocking a Singleton requires module-level monkey-
        patching, which is fragile.
      </p>
    </div>

    <div class="callout callout-con">
      <div class="callout-title">❌ Con — Global mutable state is a bug magnet</div>
      <p>
        Every part of the application can mutate the Singleton. In a large
        codebase, tracking down <em>who</em> changed the theme (or locale, or
        feature flag) at a given moment becomes a debugging nightmare.
      </p>
    </div>

    <div class="callout callout-warn mt-2">
      <div class="callout-title">⚠️ Warning — Concurrency in other languages</div>
      <p>
        In multi-threaded environments (Java, C#, Go) a naïve Singleton is not
        thread-safe. Two threads can both see <code>instance === null</code>
        simultaneously and create two instances. JavaScript's single-threaded
        event loop sidesteps this, but it is a critical concern elsewhere.
      </p>
    </div>

    <!-- Full comparison table -->
    <div class="mt-3">
      <table class="comparison-table" aria-label="Singleton pros and cons comparison">
        <thead>
          <tr>
            <th>Aspect</th>
            <th>Singleton Behaviour</th>
            <th>Verdict</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td><strong>Instance count</strong></td>
            <td>Exactly one, enforced at runtime</td>
            <td><span class="tag tag-pro">PRO</span> Predictable</td>
          </tr>
          <tr>
            <td><strong>Memory use</strong></td>
            <td>Single allocation, lazy</td>
            <td><span class="tag tag-pro">PRO</span> Efficient</td>
          </tr>
          <tr>
            <td><strong>Testability</strong></td>
            <td>Hard to mock/reset between tests</td>
            <td><span class="tag tag-con">CON</span> Painful</td>
          </tr>
          <tr>
            <td><strong>Coupling</strong></td>
            <td>Callers depend on concrete class</td>
            <td><span class="tag tag-con">CON</span> Tight</td>
          </tr>
          <tr>
            <td><strong>Dependency visibility</strong></td>
            <td>Hidden — not in function signature</td>
            <td><span class="tag tag-con">CON</span> Opaque</td>
          </tr>
          <tr>
            <td><strong>Thread safety</strong></td>
            <td>Needs explicit locking (non-JS)</td>
            <td><span class="tag tag-warn">WARN</span> Context-dependent</td>
          </tr>
          <tr>
            <td><strong>Subclassing</strong></td>
            <td>Awkward — static methods don't inherit cleanly</td>
            <td><span class="tag tag-warn">WARN</span> Limited</td>
          </tr>
          <tr>
            <td><strong>Global access</strong></td>
            <td>Available everywhere, always</td>
            <td><span class="tag tag-pro">PRO</span> / <span class="tag tag-con">CON</span> Double-edged</td>
          </tr>
        </tbody>
      </table>
    </div>
  </section>

  <hr class="divider" />

  <!-- ============================================================
       SECTION 5 — WHEN TO USE / AVOID
       ============================================================ -->
  <section class="section" aria-labelledby="when-heading">
    <div class="section-header">
      <span class="section-icon" aria-hidden="true">🗺️</span>
      <h2 class="section-title" id="when-heading">When to Use (and Avoid) Singletons</h2>
    </div>

    <div class="grid-2">
      <div class="card">
        <div class="card-title" style="color:var(--pro-text)">✅ Good Use Cases</div>
        <ul class="feature-list mt-1">
          <li data-icon="🎨">UI theme / dark-mode state (this demo)</li>
          <li data-icon="🌐">Internationalisation (i18n) locale manager</li>
          <li data-icon="🔌">Database connection pool (one pool, many connections)</li>
          <li data-icon="📋">Application-wide logger / telemetry</li>
          <li data-icon="🚩">Feature flag / remote config cache</li>
          <li data-icon="🔔">Event bus / message broker</li>
          <li data-icon="⚙️">App configuration loaded once at startup</li>
        </ul>
      </div>
      <div class="card">
        <div class="card-title" style="color:var(--con-text)">❌ Poor Use Cases</div>
        <ul class="feature-list mt-1">
          <li data-icon="🧪">Any class you need to unit-test in isolation</li>
          <li data-icon="🔀">State that varies per user / per request (server-side)</li>
          <li data-icon="🧩">Services that have multiple valid configurations</li>
          <li data-icon="🏗️">Classes that need to be subclassed or swapped</li>
          <li data-icon="🔄">State that changes frequently and unpredictably</li>
          <li data-icon="📦">Data that belongs to a component, not the whole app</li>
          <li data-icon="🌊">Anything in a concurrent / multi-threaded context (non-JS)</li>
        </ul>
      </div>
    </div>

