        <div class="flow-branch" style="margin-left:50%; width:50%">
          <div class="flow-branch-item">
            <div class="flow-branch-label">NO</div>
            <div class="flow-arrow">↓</div>
            <div class="flow-box result-no">⚠️ Consider DI<br/><small>Pass it as a parameter</small></div>
          </div>
          <div class="flow-branch-item">
            <div class="flow-branch-label">YES</div>
            <div class="flow-arrow">↓</div>
