        <div class="card-title">ES Module Singleton</div>
        <div class="card-body">
          JavaScript modules are cached after the first import. Exporting a
          plain object or instance from a module gives you Singleton behaviour
          without a class — simpler and more idiomatic in modern JS.
        </div>
        <pre style="margin-top:0.8rem"><code><span class="cm">// themeStore.js — module-level singleton</span>
<span class="kw">let</span> theme = <span class="str">'light'</span>;
<span class="kw">const</span> listeners = <span class="kw">new</span> <span class="fn">Set</span>();

<span class="kw">export const</span> themeStore = {
  <span class="fn">get</span>: () => theme,
  <span class="fn">toggle</span>: () => {
    theme = theme === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    listeners.<span class="fn">forEach</span>(fn => <span class="fn">fn</span>(theme));
  },
  <span class="fn">subscribe</span>: fn => listeners.<span class="fn">add</span>(fn),
};</code></pre>
