  <script>
    /* ═══════════════════════════════════════════════
       THE SINGLETON — ThemeManager
       ═══════════════════════════════════════════════

       Classic singleton structure:
         1. Private static _instance field
         2. Private constructor (enforced by convention in JS)
         3. Public static getInstance() factory method
         4. All state & behaviour on the single instance
    ═══════════════════════════════════════════════ */
    class ThemeManager {
      // ── Static private slot that holds the one instance ──
      static _instance = null;

      // ── Called only once, ever ──
      constructor() {
        if (ThemeManager._instance) {
          // Enforce singleton — return the existing instance
          return ThemeManager._instance;
        }

        // ── Internal state ──
        this._theme         = 'light';
        this._toggleCount   = 0;
        this._listeners     = new Set();
        this._lastChanged   = null;
        this._instanceId    = `tm_${Date.now().toString(36)}`;

        // Restore persisted preference
        const saved = localStorage.getItem('theme-preference');
        if (saved === 'dark' || saved === 'light') {
          this._theme = saved;
        } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
          this._theme = 'dark';
        }

        // Lock in the singleton
        ThemeManager._instance = this;
      }

      /* ── Public factory — always returns the same object ── */
      static getInstance() {
        if (!ThemeManager._instance) {
          new ThemeManager(); // triggers constructor which sets _instance
        }
        return ThemeManager._instance;
      }

      /* ── Getters ── */
      get theme()       { return this._theme; }
      get toggleCount() { return this._toggleCount; }
      get instanceId()  { return this._instanceId; }
      get listenerCount(){ return this._listeners.size; }
      get lastChanged() { return this._lastChanged; }

      /* ── Subscribe / unsubscribe ── */
      subscribe(fn) {
        this._listeners.add(fn);
        return () => this._listeners.delete(fn); // returns an unsubscribe fn
      }

      /* ── Notify all listeners ── */
      _notify() {
        this._listeners.forEach(fn => fn(this._theme));
      }

      /* ── Core toggle ── */
      toggle() {
        this._theme       = this._theme === 'light' ? 'dark' : 'light';
        this._toggleCount += 1;
        this._lastChanged = new Date();
        localStorage.setItem('theme-preference', this._theme);
        this._notify();
      }

      /* ── Set explicitly ── */
      setTheme(t) {
        if (t !== this._theme && (t === 'light' || t === 'dark')) {
          this._theme       = t;
          this._toggleCount += 1;
          this._lastChanged = new Date();
          localStorage.setItem('theme-preference', this._theme);
          this._notify();
        }
      }
    }

    /* ═══════════════════════════════════════════════
       BOOTSTRAP — wire everything up
    ═══════════════════════════════════════════════ */
    (function bootstrap() {

      // ── Grab the singleton ──
      const tm = ThemeManager.getInstance();

      // ── Verify it truly is a singleton ──
      const tm2 = ThemeManager.getInstance();
      console.assert(tm === tm2, 'Singleton violated — two different instances!');
      console.log('Same instance?', tm === tm2, '← should be true');
      console.log('Instance ID:', tm.instanceId);

      // ── DOM refs ──
      const body        = document.body;
      const toggleBtn   = document.getElementById('themeToggle');
      const toggleIcon  = document.getElementById('toggleIcon');
      const toggleLabel = document.getElementById('toggleLabel');

      // Inspector fields
      const insId        = document.getElementById('ins-id');
      const insTheme     = document.getElementById('ins-theme');
      const insCount     = document.getElementById('ins-count');
      const insListeners = document.getElementById('ins-listeners');
      const insTime      = document.getElementById('ins-time');
      const insPersisted = document.getElementById('ins-persisted');

      /* ── Apply theme to DOM ── */
      function applyTheme(theme) {
        body.className = `theme-${theme}`;
        toggleIcon.textContent  = theme === 'dark' ? '☀️' : '🌙';
        toggleLabel.textContent = theme === 'dark' ? 'Light Mode' : 'Dark Mode';
        updateInspector();
      }

      /* ── Update the live inspector panel ── */
      function updateInspector() {
        insId.textContent        = tm.instanceId;
        insTheme.textContent     = `"${tm.theme}"`;
        insCount.textContent     = tm.toggleCount;
        insListeners.textContent = tm.listenerCount;
        insTime.textContent      = tm.lastChanged
          ? tm.lastChanged.toLocaleTimeString()
          : 'never';
        insPersisted.textContent = localStorage.getItem('theme-preference')
          ? `"${localStorage.getItem('theme-preference')}"` : 'null';
      }

      /* ── Subscribe to theme changes ── */
      tm.subscribe(applyTheme);

      /* ── Wire toggle button ── */
      toggleBtn.addEventListener('click', () => tm.toggle());

      /* ── Apply initial theme without incrementing toggleCount ── */
      applyTheme(tm.theme);

      /* ═══════════════════════════════════════
         SCROLL REVEAL
      ═══════════════════════════════════════ */
      const observer = new IntersectionObserver(
        entries => entries.forEach(e => {
          if (e.isIntersecting) {
            e.target.classList.add('visible');
            observer.unobserve(e.target);
          }
        }),
        { threshold: 0.1 }
      );

      document.querySelectorAll('.reveal').forEach(el => observer.observe(el));

      /* ═══════════════════════════════════════
         CODE BLOCK — render highlighted source
      ═══════════════════════════════════════ */
      const code = [
        '<span class="cm">// Retrieve (or create) the singleton</span>',
        '<span class="kw">const</span> tm = <span class="cls">ThemeManager</span>.<span class="fn">getInstance</span>();',
        '',
        '<span class="cm">// Subscribe a listener — called on every theme change</span>',
        '<span class="kw">const</span> unsub = tm.<span class="fn">subscribe</span>(theme => {',
        '  document.body.className = <span class="str">`theme-${theme}`</span>;',
        '});',
        '',
        '<span class="cm">// Toggle between light ↔ dark</span>',
        'tm.<span class="fn">toggle</span>();',
        '',
        '<span class="cm">// Proof: both variables point to the SAME object</span>',
        '<span class="kw">const</span> tm2 = <span class="cls">ThemeManager</span>.<span class="fn">getInstance</span>();',
        'console.<span class="fn">assert</span>(tm === tm2); <span class="cm">// ✅ always true</span>',
        '',
        '<span class="cm">// Read state</span>',
        'console.<span class="fn">log</span>(tm.theme);        <span class="cm">// "dark" | "light"</span>',
        'console.<span class="fn">log</span>(tm.toggleCount); <span class="cm">// number of toggles</span>',
        'console.<span class="fn">log</span>(tm.instanceId);  <span class="cm">// unique stamp</span>',
        '',
        '<span class="cm">// Clean up when done</span>',
        '<span class="fn">unsub</span>();',
      ].join('\n');

      document.getElementById('codeBlock').innerHTML = code;

    })(); // end bootstrap IIFE
  </script>
</body>
</html>
```

---

## What's Inside & Why

### 🏗️ The Singleton Structure
| Piece | Purpose |
|---|---|
| `static _instance = null` | The one slot that holds the shared object |
| `constructor()` guard | Returns the existing instance if called twice |
| `static getInstance()` | The only public entry point — creates lazily |
| `subscribe / _notify` | Built-in Observer so consumers react to changes |

### 🎨 Theming Approach
- **CSS Custom Properties** on `body.theme-light / body.theme-dark` — swapping the class is the only DOM write needed; every element updates via cascade
- `transition` on every property ensures smooth 350ms animations

### 🔬 Live State Inspector
The panel at the top shows the singleton's internal state in real time — **instance ID, toggle count, listener count, last-changed time, and localStorage value** — making the pattern's behaviour concrete and visible.

### 📋 Singleton vs DI Summary
- **Use Singleton** for app-wide, single-config resources: theme, logger, feature flags, connection pool
- **Use DI** when you need testability, swappable implementations, explicit contracts, or framework integration

