<pre>
<span class="cmt">// ─── Singleton: ThemeManager ───────────────────────────────</span>
<span class="kw">class</span> <span class="cls">ThemeManager</span> {
  <span class="kw">static</span> #instance = <span class="kw">null</span>;   <span class="cmt">// private static field</span>
  #theme     = <span class="str">'light'</span>;
  #observers = <span class="kw">new</span> <span class="cls">Set</span>();
  #toggleCount = <span class="num">0</span>;

  <span class="cmt">// Private constructor — blocks direct instantiation</span>
  <span class="fn">constructor</span>() {
    <span class="kw">if</span> (<span class="cls">ThemeManager</span>.#instance) {
      <span class="kw">throw new</span> <span class="cls">Error</span>(<span class="str">'Use ThemeManager.getInstance()'</span>);
    }
    <span class="cmt">// Restore persisted preference</span>
    <span class="kw">const</span> saved = localStorage.<span class="fn">getItem</span>(<span class="str">'theme'</span>);
    <span class="kw">const</span> sys   = matchMedia(<span class="str">'(prefers-color-scheme:dark)'</span>).matches;
    <span class="kw">this</span>.#theme = saved ?? (sys ? <span class="str">'dark'</span> : <span class="str">'light'</span>);
  }

  <span class="cmt">// The single global access point</span>
  <span class="kw">static</span> <span class="fn">getInstance</span>() {
    <span class="kw">if</span> (!<span class="cls">ThemeManager</span>.#instance) {
      <span class="cls">ThemeManager</span>.#instance = <span class="kw">new</span> <span class="cls">ThemeManager</span>();
    }
    <span class="kw">return</span> <span class="cls">ThemeManager</span>.#instance;
  }

  <span class="fn">subscribe</span>(fn)   { <span class="kw">this</span>.#observers.<span class="fn">add</span>(fn);    }
  <span class="fn">unsubscribe</span>(fn) { <span class="kw">this</span>.#observers.<span class="fn">delete</span>(fn); }

  <span class="fn">toggle</span>() {
    <span class="kw">this</span>.#theme = <span class="kw">this</span>.#theme === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    <span class="kw">this</span>.#toggleCount++;
    localStorage.<span class="fn">setItem</span>(<span class="str">'theme'</span>, <span class="kw">this</span>.#theme);
    <span class="kw">this</span>.#observers.<span class="fn">forEach</span>(fn => <span class="fn">fn</span>(<span class="kw">this</span>.#theme));
  }

  <span class="fn">getTheme</span>()      { <span class="kw">return</span> <span class="kw">this</span>.#theme;       }
  <span class="fn">getToggleCount</span>(){ <span class="kw">return</span> <span class="kw">this</span>.#toggleCount; }
  <span class="fn">getObserverCount</span>(){ <span class="kw">return</span> <span class="kw">this</span>.#observers.size; }
}
</pre>
