      --badge-pro-txt: #065f46;
      --badge-con-bg:  #fee2e2;
      --badge-con-txt: #991b1b;
      --badge-tip-bg:  #fef3c7;
      --badge-tip-txt: #92400e;
      --toggle-bg:     #cbd5e0;
      --toggle-knob:   #ffffff;
      --nav-bg:        #ffffff;
      --table-head:    #f7fafc;
      --table-stripe:  #f0f4f8;
      --progress-bg:   #e2e8f0;
    }

    [data-theme="dark"] {
      --bg-primary:    #0f1117;
      --bg-secondary:  #1a1d2e;
      --bg-card:       #1e2235;
      --bg-code:       #12151f;
      --text-primary:  #e2e8f0;
      --text-secondary:#a0aec0;
      --text-muted:    #718096;
      --accent:        #818cf8;
      --accent-hover:  #6366f1;
      --accent-light:  #1e1b4b;
      --border:        #2d3250;
      --shadow:        rgba(0,0,0,0.4);
      --badge-pro-bg:  #064e3b;
      --badge-pro-txt: #6ee7b7;
      --badge-con-bg:  #7f1d1d;
      --badge-con-txt: #fca5a5;
      --badge-tip-bg:  #78350f;
      --badge-tip-txt: #fde68a;
      --toggle-bg:     #4f46e5;
      --toggle-knob:   #ffffff;
      --nav-bg:        #1a1d2e;
      --table-head:    #252844;
      --table-stripe:  #1a1d2e;
      --progress-bg:   #2d3250;
    }

    /* ── Reset & Base ── */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    html { scroll-behavior: smooth; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      line-height: 1.7;
      transition: background var(--transition), color var(--transition);
      min-height: 100vh;
    }

    /* ── Navigation ── */
    nav {
      position: sticky;
      top: 0;
      z-index: 100;
      background: var(--nav-bg);
      border-bottom: 1px solid var(--border);
      box-shadow: 0 2px 12px var(--shadow);
      transition: background var(--transition), border-color var(--transition);
    }

    .nav-inner {
      max-width: 1100px;
      margin: 0 auto;
      padding: 0 1.5rem;
      height: 64px;
      display: flex;
      align-items: center;
      justify-content: space-between;
    }

    .nav-logo {
      display: flex;
      align-items: center;
      gap: 0.6rem;
      font-weight: 700;
      font-size: 1.1rem;
      color: var(--accent);
      text-decoration: none;
    }

    .nav-logo .logo-icon {
      width: 32px;
      height: 32px;
      background: var(--accent);
      border-radius: 8px;
      display: grid;
      place-items: center;
      color: #fff;
      font-size: 0.9rem;
      font-weight: 900;
    }

    .nav-links {
      display: flex;
      gap: 1.5rem;
      list-style: none;
    }

    .nav-links a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.9rem;
      font-weight: 500;
      transition: color var(--transition);
    }

    .nav-links a:hover { color: var(--accent); }

    .nav-right { display: flex; align-items: center; gap: 1rem; }

    /* ── Toggle Switch ── */
    .theme-toggle {
      display: flex;
      align-items: center;
      gap: 0.6rem;
      cursor: pointer;
      user-select: none;
    }

    .toggle-label { font-size: 0.8rem; color: var(--text-muted); font-weight: 500; }

    .toggle-track {
      width: 52px;
      height: 28px;
      background: var(--toggle-bg);
      border-radius: 14px;
      position: relative;
      transition: background var(--transition);
      cursor: pointer;
      border: none;
      outline: none;
      padding: 0;
    }

    .toggle-track:focus-visible {
      outline: 2px solid var(--accent);
      outline-offset: 2px;
    }

    .toggle-knob {
      position: absolute;
      top: 3px;
      left: 3px;
      width: 22px;
      height: 22px;
      background: var(--toggle-knob);
      border-radius: 50%;
      transition: transform var(--transition), background var(--transition);
      display: grid;
      place-items: center;
      font-size: 12px;
      box-shadow: 0 1px 4px rgba(0,0,0,0.25);
    }

    [data-theme="dark"] .toggle-knob { transform: translateX(24px); }

    /* ── Layout ── */
    .container {
      max-width: 1100px;
      margin: 0 auto;
      padding: 2rem 1.5rem 4rem;
    }

    section { margin-bottom: 3.5rem; }

    /* ── Hero ── */
    .hero {
      text-align: center;
      padding: 4rem 1rem 3rem;
    }

    .hero-badge {
      display: inline-block;
      background: var(--accent-light);
      color: var(--accent);
      font-size: 0.75rem;
      font-weight: 700;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      padding: 0.3rem 0.9rem;
      border-radius: 99px;
      margin-bottom: 1.2rem;
      border: 1px solid var(--accent);
      transition: background var(--transition), color var(--transition);
    }

    .hero h1 {
      font-size: clamp(2rem, 5vw, 3.2rem);
      font-weight: 800;
      line-height: 1.2;
      margin-bottom: 1rem;
      background: linear-gradient(135deg, var(--accent), #ec4899);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
    }

    .hero p {
      font-size: 1.1rem;
      color: var(--text-secondary);
      max-width: 600px;
      margin: 0 auto 2rem;
      transition: color var(--transition);
    }

    .hero-actions { display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap; }

    .btn {
      padding: 0.7rem 1.6rem;
      border-radius: 8px;
      font-weight: 600;
      font-size: 0.95rem;
      cursor: pointer;
      border: none;
      transition: all var(--transition);
      text-decoration: none;
      display: inline-block;
    }

    .btn-primary {
      background: var(--accent);
      color: #fff;
    }

    .btn-primary:hover { background: var(--accent-hover); transform: translateY(-1px); }

    .btn-outline {
      background: transparent;
      color: var(--accent);
      border: 2px solid var(--accent);
    }

    .btn-outline:hover { background: var(--accent-light); transform: translateY(-1px); }

    /* ── Section Headers ── */
    .section-header { margin-bottom: 1.5rem; }

    .section-header h2 {
      font-size: 1.6rem;
      font-weight: 700;
      margin-bottom: 0.4rem;
    }

    .section-header p { color: var(--text-secondary); font-size: 0.95rem; }

    .divider {
      width: 48px;
      height: 4px;
      background: var(--accent);
      border-radius: 2px;
      margin: 0.6rem 0 0.8rem;
    }

    /* ── Cards Grid ── */
    .cards-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
      gap: 1.25rem;
    }

    .card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 1.5rem;
      box-shadow: 0 2px 12px var(--shadow);
      transition: background var(--transition), border-color var(--transition),
                  box-shadow var(--transition), transform 0.2s;
    }

    .card:hover { transform: translateY(-3px); box-shadow: 0 8px 24px var(--shadow); }

    .card-icon {
      font-size: 2rem;
      margin-bottom: 0.8rem;
      display: block;
    }

    .card h3 { font-size: 1.05rem; font-weight: 700; margin-bottom: 0.5rem; }

    .card p { color: var(--text-secondary); font-size: 0.9rem; transition: color var(--transition); }

    /* ── Code Block ── */
    .code-block {
      background: var(--bg-code);
      border: 1px solid var(--border);
      border-radius: 12px;
      overflow: hidden;
      transition: background var(--transition), border-color var(--transition);
    }

    .code-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0.75rem 1rem;
      border-bottom: 1px solid var(--border);
      transition: border-color var(--transition);
    }

    .code-dots { display: flex; gap: 6px; }

    .code-dot {
      width: 12px;
      height: 12px;
      border-radius: 50%;
    }

    .dot-red   { background: #ff5f57; }
    .dot-yellow{ background: #ffbd2e; }
    .dot-green { background: #28c840; }

    .code-lang {
      font-size: 0.75rem;
      color: var(--text-muted);
      font-family: monospace;
      font-weight: 600;
    }

    .copy-btn {
      font-size: 0.75rem;
      color: var(--text-muted);
      background: none;
      border: 1px solid var(--border);
      border-radius: 5px;
      padding: 0.2rem 0.6rem;
      cursor: pointer;
      transition: all var(--transition);
    }

    .copy-btn:hover { color: var(--accent); border-color: var(--accent); }

    pre {
      padding: 1.25rem;
      overflow-x: auto;
      font-size: 0.85rem;
      line-height: 1.6;
    }

    code {
      font-family: 'Fira Code', 'Cascadia Code', Consolas, monospace;
      color: var(--text-primary);
    }

    .kw  { color: #c792ea; }
    .fn  { color: #82aaff; }
    .str { color: #c3e88d; }
    .cm  { color: #546e7a; font-style: italic; }
    .num { color: #f78c6c; }

    /* ── Stat Cards ── */
    .stats-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
      gap: 1rem;
    }

    .stat-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.25rem;
      text-align: center;
      box-shadow: 0 2px 8px var(--shadow);
      transition: background var(--transition), border-color var(--transition);
    }

    .stat-value {
      font-size: 2rem;
      font-weight: 800;
      color: var(--accent);
      display: block;
    }

    .stat-label { font-size: 0.8rem; color: var(--text-muted); margin-top: 0.2rem; }

    /* ── Progress Bars ── */
    .progress-list { display: flex; flex-direction: column; gap: 1rem; }

    .progress-item label {
      display: flex;
      justify-content: space-between;
      font-size: 0.9rem;
      font-weight: 600;
      margin-bottom: 0.4rem;
    }

    .progress-item label span { color: var(--text-muted); font-weight: 400; }

    .progress-track {
      height: 8px;
      background: var(--progress-bg);
      border-radius: 4px;
      overflow: hidden;
      transition: background var(--transition);
    }

    .progress-fill {
      height: 100%;
      border-radius: 4px;
      background: linear-gradient(90deg, var(--accent), #ec4899);
      transition: width 1s cubic-bezier(0.4,0,0.2,1);
    }

    /* ── Table ── */
    .table-wrap {
      overflow-x: auto;
      border-radius: 12px;
      border: 1px solid var(--border);
      box-shadow: 0 2px 12px var(--shadow);
      transition: border-color var(--transition);
    }

    table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.9rem;
    }

    thead th {
      background: var(--table-head);
      padding: 0.85rem 1rem;
      text-align: left;
      font-weight: 700;
      color: var(--text-secondary);
      font-size: 0.8rem;
      text-transform: uppercase;
      letter-spacing: 0.06em;
      border-bottom: 1px solid var(--border);
      transition: background var(--transition), color var(--transition);
    }

    tbody tr { transition: background var(--transition); }

    tbody tr:nth-child(even) { background: var(--table-stripe); }

    tbody tr:hover { background: var(--accent-light); }

    tbody td {
      padding: 0.85rem 1rem;
      border-bottom: 1px solid var(--border);
      color: var(--text-secondary);
      transition: color var(--transition), border-color var(--transition);
    }

    tbody tr:last-child td { border-bottom: none; }

    .tag {
      display: inline-block;
      padding: 0.2rem 0.6rem;
      border-radius: 99px;
      font-size: 0.75rem;
      font-weight: 600;
    }

    .tag-green { background: var(--badge-pro-bg); color: var(--badge-pro-txt); }
    .tag-red   { background: var(--badge-con-bg); color: var(--badge-con-txt); }
    .tag-yellow{ background: var(--badge-tip-bg); color: var(--badge-tip-txt); }

    /* ── Alert / Callout ── */
    .callout {
      display: flex;
      gap: 1rem;
      padding: 1.1rem 1.25rem;
      border-radius: 10px;
      border-left: 4px solid;
      margin-bottom: 1rem;
      transition: background var(--transition);
    }

    .callout-icon { font-size: 1.3rem; flex-shrink: 0; }

    .callout-body h4 { font-size: 0.95rem; font-weight: 700; margin-bottom: 0.2rem; }

    .callout-body p { font-size: 0.875rem; }

    .callout-pro {
      background: var(--badge-pro-bg);
      border-color: #10b981;
      color: var(--badge-pro-txt);
    }

    .callout-con {
      background: var(--badge-con-bg);
      border-color: #ef4444;
      color: var(--badge-con-txt);
    }

    .callout-tip {
      background: var(--badge-tip-bg);
      border-color: #f59e0b;
      color: var(--badge-tip-txt);
    }

    /* ── Discussion Section ── */
    .discussion {
      background: var(--bg-secondary);
      border-radius: 16px;
      border: 1px solid var(--border);
      padding: 2.5rem;
      box-shadow: 0 4px 24px var(--shadow);
      transition: background var(--transition), border-color var(--transition);
    }

    .discussion h2 {
      font-size: 1.7rem;
      font-weight: 800;
      margin-bottom: 0.4rem;
    }

    .discussion-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1.5rem;
      margin: 1.5rem 0;
    }

    @media (max-width: 640px) {
      .discussion-grid { grid-template-columns: 1fr; }
      .nav-links { display: none; }
    }

    .disc-col h3 {
      font-size: 1.05rem;
      font-weight: 700;
      margin-bottom: 1rem;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }

    .disc-item {
      display: flex;
      gap: 0.75rem;
      margin-bottom: 0.85rem;
      padding: 0.85rem;
      border-radius: 8px;
      background: var(--bg-card);
      border: 1px solid var(--border);
      font-size: 0.875rem;
      transition: background var(--transition), border-color var(--transition);
    }

    .disc-item-icon { font-size: 1.1rem; flex-shrink: 0; }

    .disc-item-text strong { display: block; font-weight: 600; margin-bottom: 0.2rem; }

    .disc-item-text p { color: var(--text-secondary); line-height: 1.5; transition: color var(--transition); }

    .alternatives-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
      gap: 1rem;
      margin-top: 1.5rem;
    }

    .alt-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 1.1rem;
      transition: background var(--transition), border-color var(--transition);
    }

    .alt-card h4 {
      font-size: 0.95rem;
      font-weight: 700;
      margin-bottom: 0.5rem;
      color: var(--accent);
    }

    .alt-card p { font-size: 0.85rem; color: var(--text-secondary); transition: color var(--transition); }

    /* ── Form ── */
    .form-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1rem;
    }

    @media (max-width: 600px) { .form-grid { grid-template-columns: 1fr; } }

    .form-group { display: flex; flex-direction: column; gap: 0.4rem; }

    .form-group.full { grid-column: 1 / -1; }

    .form-group label { font-size: 0.85rem; font-weight: 600; color: var(--text-secondary); }

    .form-group input,
    .form-group textarea,
    .form-group select {
      background: var(--bg-primary);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 0.65rem 0.9rem;
      color: var(--text-primary);
      font-size: 0.9rem;
      font-family: inherit;
      transition: border-color var(--transition), background var(--transition);
      outline: none;
    }

    .form-group input:focus,
    .form-group textarea:focus,
    .form-group select:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px var(--accent-light);
    }

    .form-group textarea { min-height: 100px; resize: vertical; }

    /* ── Toast ── */
    #toast {
      position: fixed;
      bottom: 2rem;
      right: 2rem;
      background: var(--accent);
      color: #fff;
      padding: 0.75rem 1.25rem;
      border-radius: 10px;
      font-size: 0.9rem;
      font-weight: 600;
      box-shadow: 0 4px 20px rgba(0,0,0,0.3);
      transform: translateY(100px);
      opacity: 0;
      transition: all 0.4s cubic-bezier(0.34,1.56,0.64,1);
      z-index: 999;
      pointer-events: none;
    }

    #toast.show { transform: translateY(0); opacity: 1; }

    /* ── Footer ── */
    footer {
      background: var(--bg-secondary);
      border-top: 1px solid var(--border);
      padding: 2rem 1.5rem;
      text-align: center;
      color: var(--text-muted);
      font-size: 0.85rem;
      transition: background var(--transition), border-color var(--transition);
    }

    footer strong { color: var(--accent); }

    /* ── Singleton Visualizer ── */
    .visualizer {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 1.5rem;
      box-shadow: 0 2px 12px var(--shadow);
      transition: background var(--transition), border-color var(--transition);
    }

    .vis-row {
      display: flex;
      align-items: center;
      gap: 1rem;
      margin-bottom: 1rem;
      flex-wrap: wrap;
    }

    .vis-box {
      background: var(--bg-code);
      border: 2px solid var(--border);
      border-radius: 8px;
      padding: 0.6rem 1rem;
      font-size: 0.8rem;
      font-family: monospace;
      font-weight: 600;
      color: var(--text-secondary);
      transition: all var(--transition);
    }

    .vis-box.active {
      border-color: var(--accent);
      color: var(--accent);
      background: var(--accent-light);
    }

    .vis-arrow { color: var(--text-muted); font-size: 1.2rem; }

    .vis-singleton {
      background: var(--accent);
      color: #fff;
      border-radius: 10px;
      padding: 0.8rem 1.2rem;
      font-size: 0.85rem;
      font-family: monospace;
      font-weight: 700;
      text-align: center;
      min-width: 160px;
    }

    #instance-count {
      font-size: 1.5rem;
      font-weight: 800;
      display: block;
    }

    #theme-log {
      background: var(--bg-code);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 0.75rem 1rem;
      font-size: 0.78rem;
      font-family: monospace;
      color: var(--text-secondary);
      max-height: 100px;
      overflow-y: auto;
      transition: background var(--transition), border-color var(--transition);
    }

    #theme-log p { margin-bottom: 0.2rem; }

    #theme-log .log-entry { color: var(--accent); }
  </style>
</head>
<body data-theme="light">

<!-- ── Navigation ── -->
<nav>
  <div class="nav-inner">
    <a class="nav-logo" href="#">
      <div class="logo-icon">S</div>
      SingletonUI
    </a>
    <ul class="nav-links">
      <li><a href="#overview">Overview</a></li>
      <li><a href="#demo">Demo</a></li>
      <li><a href="#code">Code</a></li>
      <li><a href="#discussion">Discussion</a></li>
    </ul>
    <div class="nav-right">
      <span class="toggle-label" id="theme-label">Light</span>
      <button class="toggle-track" id="themeToggle" aria-label="Toggle theme" role="switch" aria-checked="false">
        <div class="toggle-knob" id="toggleKnob">☀️</div>
      </button>
    </div>
  </div>
