<script>
  /* ── ThemeManager Singleton ── */
  class ThemeManager {
    static #instance = null;

    constructor() {
      if (ThemeManager.#instance) {
        throw new Error("Use ThemeManager.getInstance() — only one instance allowed.");
      }
      this.theme       = this._loadTheme();
      this.subscribers = [];
      this.toggleCount = 0;
      this._apply();
    }

    static getInstance() {
      if (!ThemeManager.#instance) {
        ThemeManager.#instance = new ThemeManager();
      }
      return ThemeManager.#instance;
    }

    toggle() {
      this.theme = this.theme === "light" ? "dark" : "light";
      this.toggleCount++;
      this._apply();
      this._save();
      this._notify();
    }

    subscribe(callback) {
      this.subscribers.push(callback);
      // Return an unsubscribe function
      return () => {
        this.subscribers = this.subscribers.filter(cb => cb !== callback);
      };
    }

    _apply()  { document.body.dataset.theme = this.theme; }
    _save()   { try { localStorage.setItem("theme", this.theme); } catch(e) {} }
    _notify() { this.subscribers.forEach(cb => cb(this.theme)); }

    _loadTheme() {
      try {
        const stored = localStorage.getItem("theme");
        if (stored === "light" || stored === "dark") return stored;
      } catch(e) {}
      return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
    }
  }

  /* ── Bootstrap ── */
  const tm = ThemeManager.getInstance();

  // Verify singleton — a second call must return the same reference
  const tm2 = ThemeManager.getInstance();
  console.assert(tm === tm2, "Singleton violated! Different instances returned.");
  console.log("Singleton check passed — tm === tm2:", tm === tm2);

  /* ── UI element refs ── */
  const toggleBtn          = document.getElementById("themeToggle");
  const toggleKnob         = document.getElementById("toggleKnob");
  const themeLabel         = document.getElementById("theme-label");
  const instanceCountEl    = document.getElementById("instanceCount");
  const toggleCountEl      = document.getElementById("toggleCount");
  const currentThemeEl     = document.getElementById("currentThemeDisplay");
  const themeLog           = document.getElementById("theme-log");
  const instanceCountVis   = document.getElementById("instance-count");

  /* ── Sync UI to current theme ── */
  function syncUI(theme) {
    const isDark = theme === "dark";
    toggleKnob.textContent    = isDark ? "🌙" : "☀️";
    themeLabel.textContent    = isDark ? "Dark" : "Light";
    toggleBtn.setAttribute("aria-checked", isDark ? "true" : "false");
    currentThemeEl.textContent = isDark ? "Dark" : "Light";
    toggleCountEl.textContent  = tm.toggleCount;
    instanceCountEl.textContent = "1";      // always 1 — it's a singleton
    instanceCountVis.textContent = "1 instance";

    // Log entry
    const entry = document.createElement("p");
    entry.className = "log-entry";
    entry.textContent =
      `▶ theme changed → "${theme}" (toggle #${tm.toggleCount}, ts: ${Date.now()})`;
    themeLog.appendChild(entry);
    themeLog.scrollTop = themeLog.scrollHeight;
  }

  /* ── Subscribe three "components" to demonstrate observer integration ── */
  // Subscriber 1: NavBar
  const unsubNav = tm.subscribe(theme => {
    console.log(`[NavBar] received theme: ${theme}`);
  });

  // Subscriber 2: Cards
  const unsubCards = tm.subscribe(theme => {
    console.log(`[Cards] received theme: ${theme}`);
  });

  // Subscriber 3: Main UI updater
  const unsubUI = tm.subscribe(theme => {
    syncUI(theme);
  });

  /* ── Toggle button handler ── */
  toggleBtn.addEventListener("click", () => tm.toggle());

  /* ── Also sync on load (theme may have been restored from localStorage) ── */
  syncUI(tm.theme);

  /* ── Copy code button ── */
  function copyCode() {
    const code = document.querySelector("pre code").textContent;
    navigator.clipboard.writeText(code)
      .then(() => showToast("Code copied to clipboard!"))
      .catch(() => showToast("Copy failed — please select manually."));
  }

  /* ── Toast helper ── */
  function showToast(msg) {
    const toast = document.getElementById("toast");
    toast.textContent = msg;
    toast.classList.add("show");
    setTimeout(() => toast.classList.remove("show"), 2800);
  }

  /* ── Demonstrate that getInstance() always returns the same object ── */
  // Try to instantiate directly (should throw)
  try {
    const illegal = new ThemeManager();
  } catch (e) {
    console.log("Direct construction blocked:", e.message);
  }
</script>
</body>
</html>
