      --pro-bg:        #ecfdf5;
      --pro-border:    #6ee7b7;
      --pro-text:      #065f46;
      --con-bg:        #fef2f2;
      --con-border:    #fca5a5;
      --con-text:      #7f1d1d;
      --alt-bg:        #eff6ff;
      --alt-border:    #93c5fd;
      --alt-text:      #1e3a8a;
    }

    [data-theme="dark"] {
      --bg-primary:    #0f1117;
      --bg-secondary:  #1a1d27;
      --bg-card:       #1e2130;
      --bg-code:       #252a3a;
      --border:        #2d3348;
      --text-primary:  #e2e8f0;
      --text-secondary:#a0aec0;
      --text-muted:    #718096;
      --accent:        #818cf8;
      --accent-hover:  #a5b4fc;
      --accent-light:  #1e1b4b;
      --success:       #34d399;
      --success-light: #064e3b;
      --warning:       #fbbf24;
      --warning-light: #451a03;
      --danger:        #f87171;
      --danger-light:  #450a0a;
      --shadow:        0 2px 12px rgba(0,0,0,0.4);
      --shadow-lg:     0 8px 32px rgba(0,0,0,0.6);
      --toggle-bg:     #4f46e5;
      --toggle-knob:   #ffffff;
      --pro-bg:        #064e3b;
      --pro-border:    #059669;
      --pro-text:      #6ee7b7;
      --con-bg:        #450a0a;
      --con-border:    #dc2626;
      --con-text:      #fca5a5;
      --alt-bg:        #1e3a8a;
      --alt-border:    #3b82f6;
      --alt-text:      #bfdbfe;
    }

    /* ── Reset & base ── */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      line-height: 1.7;
      transition: background var(--transition), color var(--transition);
      min-height: 100vh;
    }

    /* ── Layout ── */
    .container {
      max-width: 960px;
      margin: 0 auto;
      padding: 0 1.25rem;
    }

    /* ── Header / Nav ── */
    header {
      background: var(--bg-secondary);
      border-bottom: 1px solid var(--border);
      box-shadow: var(--shadow);
      position: sticky;
      top: 0;
      z-index: 100;
      transition: background var(--transition), border-color var(--transition);
    }

    nav {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0.9rem 1.25rem;
      max-width: 960px;
      margin: 0 auto;
    }

    .nav-brand {
      display: flex;
      align-items: center;
      gap: 0.6rem;
      font-weight: 700;
      font-size: 1.15rem;
      color: var(--accent);
      text-decoration: none;
    }

    .nav-brand .logo { font-size: 1.4rem; }

    .nav-links {
      display: flex;
      gap: 1.5rem;
      list-style: none;
    }

    .nav-links a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.9rem;
      font-weight: 500;
      transition: color var(--transition);
    }

    .nav-links a:hover { color: var(--accent); }

    .nav-right {
      display: flex;
      align-items: center;
      gap: 1rem;
    }

    /* ── Toggle switch ── */
    .theme-toggle {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      cursor: pointer;
      user-select: none;
    }

    .theme-toggle .icon { font-size: 1rem; }

    .toggle-track {
      width: 48px;
      height: 26px;
      background: var(--toggle-bg);
      border-radius: 999px;
      position: relative;
      transition: background var(--transition);
      cursor: pointer;
      border: none;
      outline: none;
      padding: 0;
    }

    .toggle-track:focus-visible {
      box-shadow: 0 0 0 3px var(--accent);
    }

    .toggle-knob {
      position: absolute;
      top: 3px;
      left: 3px;
      width: 20px;
      height: 20px;
      background: var(--toggle-knob);
      border-radius: 50%;
      transition: transform var(--transition), background var(--transition);
      box-shadow: 0 1px 4px rgba(0,0,0,0.3);
    }

    [data-theme="dark"] .toggle-knob { transform: translateX(22px); }

    /* ── Hero ── */
    .hero {
      background: linear-gradient(135deg, var(--accent-light) 0%, var(--bg-secondary) 100%);
      border-bottom: 1px solid var(--border);
      padding: 4rem 1.25rem;
      text-align: center;
      transition: background var(--transition), border-color var(--transition);
    }

    .hero-badge {
      display: inline-block;
      background: var(--accent-light);
      color: var(--accent);
      border: 1px solid var(--accent);
      border-radius: 999px;
      font-size: 0.78rem;
      font-weight: 600;
      padding: 0.25rem 0.85rem;
      margin-bottom: 1rem;
      letter-spacing: 0.05em;
      text-transform: uppercase;
    }

    .hero h1 {
      font-size: clamp(1.8rem, 4vw, 2.8rem);
      font-weight: 800;
      color: var(--text-primary);
      margin-bottom: 0.75rem;
      line-height: 1.2;
    }

    .hero h1 span { color: var(--accent); }

    .hero p {
      font-size: 1.05rem;
      color: var(--text-secondary);
      max-width: 580px;
      margin: 0 auto 1.75rem;
    }

    .hero-actions { display: flex; gap: 0.75rem; justify-content: center; flex-wrap: wrap; }

    /* ── Buttons ── */
    .btn {
      display: inline-flex;
      align-items: center;
      gap: 0.4rem;
      padding: 0.6rem 1.3rem;
      border-radius: 8px;
      font-size: 0.92rem;
      font-weight: 600;
      cursor: pointer;
      border: none;
      transition: all var(--transition);
      text-decoration: none;
    }

    .btn-primary {
      background: var(--accent);
      color: #fff;
    }
    .btn-primary:hover { background: var(--accent-hover); transform: translateY(-1px); box-shadow: var(--shadow); }

    .btn-outline {
      background: transparent;
      color: var(--accent);
      border: 2px solid var(--accent);
    }
    .btn-outline:hover { background: var(--accent-light); transform: translateY(-1px); }

    .btn-success { background: var(--success); color: #fff; }
    .btn-success:hover { filter: brightness(1.1); transform: translateY(-1px); }

    .btn-danger { background: var(--danger); color: #fff; }
    .btn-danger:hover { filter: brightness(1.1); transform: translateY(-1px); }

    .btn-warning { background: var(--warning); color: #fff; }
    .btn-warning:hover { filter: brightness(1.1); transform: translateY(-1px); }

    /* ── Main content ── */
    main { padding: 3rem 0; }

    section { margin-bottom: 3.5rem; }

    .section-header {
      margin-bottom: 1.5rem;
    }

    .section-header h2 {
      font-size: 1.5rem;
      font-weight: 700;
      color: var(--text-primary);
      margin-bottom: 0.35rem;
    }

    .section-header p {
      color: var(--text-secondary);
      font-size: 0.95rem;
    }

    .section-divider {
      height: 1px;
      background: var(--border);
      margin: 0.75rem 0 1.5rem;
      transition: background var(--transition);
    }

    /* ── Cards ── */
    .card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.5rem;
      box-shadow: var(--shadow);
      transition: background var(--transition), border-color var(--transition), box-shadow var(--transition);
    }

    .card:hover { box-shadow: var(--shadow-lg); }

    .card-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 1.25rem;
    }

    .card-icon {
      font-size: 2rem;
      margin-bottom: 0.75rem;
    }

    .card h3 {
      font-size: 1.05rem;
      font-weight: 700;
      margin-bottom: 0.4rem;
      color: var(--text-primary);
    }

    .card p {
      font-size: 0.9rem;
      color: var(--text-secondary);
    }

    /* ── Alert / callout boxes ── */
    .alert {
      display: flex;
      gap: 0.75rem;
      padding: 1rem 1.25rem;
      border-radius: 10px;
      border-left: 4px solid;
      margin-bottom: 1rem;
      font-size: 0.92rem;
    }

    .alert-icon { font-size: 1.1rem; flex-shrink: 0; }

    .alert-success {
      background: var(--success-light);
      border-color: var(--success);
      color: var(--success);
      transition: background var(--transition);
    }

    .alert-warning {
      background: var(--warning-light);
      border-color: var(--warning);
      color: var(--warning);
      transition: background var(--transition);
    }

    .alert-danger {
      background: var(--danger-light);
      border-color: var(--danger);
      color: var(--danger);
      transition: background var(--transition);
    }

    .alert-info {
      background: var(--accent-light);
      border-color: var(--accent);
      color: var(--accent);
      transition: background var(--transition);
    }

    .alert-body { color: var(--text-primary); }
    .alert-body strong { color: inherit; }

    /* ── Code block ── */
    .code-block {
      background: var(--bg-code);
      border: 1px solid var(--border);
      border-radius: 10px;
      overflow: hidden;
      transition: background var(--transition), border-color var(--transition);
    }

    .code-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0.6rem 1rem;
      background: var(--border);
      transition: background var(--transition);
    }

    .code-dots { display: flex; gap: 6px; }
    .code-dot {
      width: 12px; height: 12px;
      border-radius: 50%;
    }
    .dot-red    { background: #ff5f57; }
    .dot-yellow { background: #febc2e; }
    .dot-green  { background: #28c840; }

    .code-lang {
      font-size: 0.75rem;
      color: var(--text-muted);
      font-weight: 600;
      letter-spacing: 0.05em;
    }

    .code-block pre {
      padding: 1.25rem;
      overflow-x: auto;
      font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
      font-size: 0.82rem;
      line-height: 1.7;
      color: var(--text-primary);
    }

    .kw  { color: #818cf8; }
    .fn  { color: #34d399; }
    .str { color: #fbbf24; }
    .cm  { color: var(--text-muted); font-style: italic; }
    .nb  { color: #f87171; }

    [data-theme="light"] .kw  { color: #4f46e5; }
    [data-theme="light"] .fn  { color: #059669; }
    [data-theme="light"] .str { color: #b45309; }
    [data-theme="light"] .nb  { color: #dc2626; }

    /* ── Table ── */
    .table-wrap {
      overflow-x: auto;
      border-radius: 10px;
      border: 1px solid var(--border);
      transition: border-color var(--transition);
    }

    table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.9rem;
    }

    thead {
      background: var(--accent-light);
      transition: background var(--transition);
    }

    thead th {
      padding: 0.8rem 1rem;
      text-align: left;
      font-weight: 700;
      color: var(--accent);
      white-space: nowrap;
    }

    tbody tr {
      border-top: 1px solid var(--border);
      transition: background var(--transition), border-color var(--transition);
    }

    tbody tr:hover { background: var(--accent-light); }

    tbody td {
      padding: 0.75rem 1rem;
      color: var(--text-secondary);
      vertical-align: top;
    }

    tbody td:first-child { color: var(--text-primary); font-weight: 600; }

    /* ── Form ── */
    .form-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
      gap: 1rem;
    }

    .form-group { display: flex; flex-direction: column; gap: 0.4rem; }

    .form-group label {
      font-size: 0.85rem;
      font-weight: 600;
      color: var(--text-secondary);
    }

    .form-group input,
    .form-group select,
    .form-group textarea {
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 0.6rem 0.85rem;
      color: var(--text-primary);
      font-size: 0.9rem;
      font-family: inherit;
      transition: border-color var(--transition), background var(--transition), box-shadow var(--transition);
      outline: none;
    }

    .form-group input:focus,
    .form-group select:focus,
    .form-group textarea:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px var(--accent-light);
    }

    .form-group textarea { resize: vertical; min-height: 90px; }

    /* ── Progress bars ── */
    .progress-list { display: flex; flex-direction: column; gap: 1rem; }

    .progress-item {}

    .progress-label {
      display: flex;
      justify-content: space-between;
      font-size: 0.85rem;
      font-weight: 600;
      color: var(--text-secondary);
      margin-bottom: 0.35rem;
    }

    .progress-track {
      height: 10px;
      background: var(--bg-code);
      border-radius: 999px;
      overflow: hidden;
      transition: background var(--transition);
    }

    .progress-fill {
      height: 100%;
      border-radius: 999px;
      transition: width 0.8s ease, background var(--transition);
    }

    .fill-accent   { background: var(--accent); }
    .fill-success  { background: var(--success); }
    .fill-warning  { background: var(--warning); }
    .fill-danger   { background: var(--danger); }

    /* ── Badge / tag ── */
    .tag-list { display: flex; flex-wrap: wrap; gap: 0.5rem; }

    .tag {
      display: inline-block;
      padding: 0.3rem 0.75rem;
      border-radius: 999px;
      font-size: 0.78rem;
      font-weight: 600;
      border: 1px solid;
      transition: background var(--transition), color var(--transition), border-color var(--transition);
    }

    .tag-accent  { background: var(--accent-light);  color: var(--accent);  border-color: var(--accent); }
    .tag-success { background: var(--success-light); color: var(--success); border-color: var(--success); }
    .tag-warning { background: var(--warning-light); color: var(--warning); border-color: var(--warning); }
    .tag-danger  { background: var(--danger-light);  color: var(--danger);  border-color: var(--danger); }

    /* ── Discussion section ── */
    .discussion {
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: 16px;
      padding: 2rem;
      transition: background var(--transition), border-color var(--transition);
    }

    .discussion h2 {
      font-size: 1.55rem;
      font-weight: 800;
      margin-bottom: 0.4rem;
    }

    .discussion .subtitle {
      color: var(--text-secondary);
      margin-bottom: 1.75rem;
      font-size: 0.95rem;
    }

    .pros-cons {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 1.25rem;
      margin-bottom: 1.75rem;
    }

    .pros-cons-box {
      border-radius: 12px;
      padding: 1.25rem 1.5rem;
      border: 1px solid;
    }

    .pros-box {
      background: var(--pro-bg);
      border-color: var(--pro-border);
      transition: background var(--transition), border-color var(--transition);
    }

    .cons-box {
      background: var(--con-bg);
      border-color: var(--con-border);
      transition: background var(--transition), border-color var(--transition);
    }

    .pros-cons-box h3 {
      font-size: 1rem;
      font-weight: 700;
      margin-bottom: 0.85rem;
      display: flex;
      align-items: center;
      gap: 0.4rem;
    }

    .pros-box h3 { color: var(--pro-text); }
    .cons-box h3 { color: var(--con-text); }

    .pros-cons-box ul {
      list-style: none;
      display: flex;
      flex-direction: column;
      gap: 0.55rem;
    }

    .pros-cons-box li {
      font-size: 0.88rem;
      display: flex;
      gap: 0.5rem;
      align-items: flex-start;
    }

    .pros-box li { color: var(--pro-text); }
    .cons-box li { color: var(--con-text); }

    .pros-cons-box li::before { flex-shrink: 0; margin-top: 0.05rem; }
    .pros-box  li::before { content: "✓"; font-weight: 700; }
    .cons-box  li::before { content: "✗"; font-weight: 700; }

    .alt-box {
      background: var(--alt-bg);
      border: 1px solid var(--alt-border);
      border-radius: 12px;
      padding: 1.25rem 1.5rem;
      margin-bottom: 1.25rem;
      transition: background var(--transition), border-color var(--transition);
    }

    .alt-box h3 {
      font-size: 1rem;
      font-weight: 700;
      color: var(--alt-text);
      margin-bottom: 0.85rem;
      display: flex;
      align-items: center;
      gap: 0.4rem;
    }

    .alt-box ul {
      list-style: none;
      display: flex;
      flex-direction: column;
      gap: 0.6rem;
    }

    .alt-box li {
      font-size: 0.88rem;
      color: var(--alt-text);
      display: flex;
      gap: 0.5rem;
      align-items: flex-start;
    }

    .alt-box li::before { content: "→"; font-weight: 700; flex-shrink: 0; margin-top: 0.05rem; }

    .verdict {
      background: var(--accent-light);
      border: 1px solid var(--accent);
      border-radius: 12px;
      padding: 1.25rem 1.5rem;
      transition: background var(--transition), border-color var(--transition);
    }

    .verdict h3 {
      font-size: 1rem;
      font-weight: 700;
      color: var(--accent);
      margin-bottom: 0.6rem;
    }

    .verdict p {
      font-size: 0.9rem;
      color: var(--text-secondary);
      line-height: 1.75;
    }

    /* ── Footer ── */
    footer {
      background: var(--bg-secondary);
      border-top: 1px solid var(--border);
      padding: 2rem 1.25rem;
      text-align: center;
      color: var(--text-muted);
      font-size: 0.85rem;
      transition: background var(--transition), border-color var(--transition);
    }

    footer strong { color: var(--accent); }

    /* ── Theme indicator toast ── */
    .toast {
      position: fixed;
      bottom: 1.5rem;
      right: 1.5rem;
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 0.7rem 1.1rem;
      box-shadow: var(--shadow-lg);
      font-size: 0.88rem;
      font-weight: 600;
      color: var(--text-primary);
      display: flex;
      align-items: center;
      gap: 0.5rem;
      transform: translateY(100px);
      opacity: 0;
      transition: transform 0.3s ease, opacity 0.3s ease, background var(--transition), border-color var(--transition);
      z-index: 999;
      pointer-events: none;
    }

    .toast.show { transform: translateY(0); opacity: 1; }

    /* ── Singleton status widget ── */
    .singleton-status {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.25rem;
      display: flex;
      align-items: center;
      gap: 1rem;
      flex-wrap: wrap;
      transition: background var(--transition), border-color var(--transition);
    }

    .status-dot {
      width: 12px; height: 12px;
      border-radius: 50%;
      background: var(--success);
      box-shadow: 0 0 0 3px var(--success-light);
      flex-shrink: 0;
      animation: pulse 2s infinite;
    }

    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50%       { opacity: 0.5; }
    }

    .status-text { font-size: 0.88rem; color: var(--text-secondary); }
    .status-text strong { color: var(--text-primary); }

    .instance-count {
      margin-left: auto;
      background: var(--accent-light);
      color: var(--accent);
      border: 1px solid var(--accent);
      border-radius: 8px;
      padding: 0.3rem 0.75rem;
      font-size: 0.8rem;
      font-weight: 700;
    }

    /* ── Responsive ── */
    @media (max-width: 600px) {
      .nav-links { display: none; }
      .hero { padding: 2.5rem 1rem; }
    }
  </style>
</head>
<body>

<!-- ═══════════════════════════════════════════
     HEADER
═══════════════════════════════════════════ -->
<header>
  <nav>
    <a class="nav-brand" href="#">
      <span class="logo">◈</span> ThemeForge
    </a>

    <ul class="nav-links">
      <li><a href="#overview">Overview</a></li>
      <li><a href="#components">Components</a></li>
      <li><a href="#code">Code</a></li>
      <li><a href="#discussion">Discussion</a></li>
    </ul>

    <div class="nav-right">
      <label class="theme-toggle" for="themeToggleBtn" title="Toggle theme">
        <span class="icon">☀️</span>
        <button
          class="toggle-track"
          id="themeToggleBtn"
          role="switch"
          aria-checked="false"
          aria-label="Toggle dark mode"
        >
          <span class="toggle-knob"></span>
        </button>
        <span class="icon">🌙</span>
      </label>
    </div>
  </nav>
</header>

<!-- ═══════════════════════════════════════════
     HERO
═══════════════════════════════════════════ -->
<div class="hero">
  <div class="hero-badge">🔒 Singleton Pattern</div>
  <h1>Theme Management with<br><span>Singleton State</span></h1>
  <p>
    A single, globally-shared <code>ThemeManager</code> instance controls every
    aspect of the UI theme — toggle it once, everything updates.
  </p>
  <div class="hero-actions">
    <button class="btn btn-primary" onclick="ThemeManager.getInstance().toggle()">
      ⚡ Toggle Theme
    </button>
    <a class="btn btn-outline" href="#discussion">📖 Read Discussion</a>
  </div>
</div>

<!-- ═══════════════════════════════════════════
     MAIN
═══════════════════════════════════════════ -->
<main>
  <div class="container">

    <!-- ── Singleton status ── -->
    <section id="overview">
      <div class="section-header">
        <h2>Singleton Instance Monitor</h2>
        <p>Live status of the <code>ThemeManager</code> singleton.</p>
      </div>
      <div class="section-divider"></div>

      <div class="singleton-status">
        <span class="status-dot"></span>
        <div class="status-text">
          <strong>ThemeManager</strong> singleton is active &mdash;
          Current theme: <strong id="currentThemeLabel">light</strong> &mdash;
          Toggle count: <strong id="toggleCount">0</strong>
        </div>
