<script>
  /**
   * ThemeManager — Singleton
   *
   * Responsibilities:
   *  1. Read the user's saved preference from localStorage (or OS default).
   *  2. Write the `data-theme` attribute on <html> so CSS variables cascade.
   *  3. Persist the choice back to localStorage.
   *  4. Notify registered observers (UI widgets) on every change.
   *  5. Enforce that only ONE instance ever exists.
   */
  class ThemeManager {
    // ── Private static field: holds the sole instance ──────────────────────
    static #instance = null;

    // ── Private constructor ─────────────────────────────────────────────────
    constructor() {
      // Guard: if someone tries `new ThemeManager()` after the singleton
      // is already created, throw immediately.
      if (ThemeManager.#instance) {
        throw new Error(
          "ThemeManager is a singleton. Use ThemeManager.getInstance()."
        );
      }

      // Determine initial theme:
      //   1. Saved preference in localStorage
      //   2. OS-level prefers-color-scheme
      //   3. Fallback to light
      const saved = localStorage.getItem("theme");
      const prefersDark = window.matchMedia(
        "(prefers-color-scheme: dark)"
      ).matches;

      this._theme        = saved ?? (prefersDark ? "dark" : "light");
      this._toggleCount  = 0;
      this._observers    = [];   // list of callback functions

      // Apply immediately on construction
      this._apply();
    }

    // ── Static access point ─────────────────────────────────────────────────
    static getInstance() {
      if (!ThemeManager.#instance) {
        ThemeManager.#instance = new ThemeManager();
      }
      return ThemeManager.#instance;
    }

    // ── Public API ──────────────────────────────────────────────────────────
    get theme()        { return this._theme; }
    get toggleCount()  { return this._toggleCount; }

    setTheme(theme) {
      if (theme !== "light" && theme !== "dark") return;
      if (theme === this._theme) return;   // no-op if same
      this._theme = theme;
      this._apply();
    }

    toggle() {
      this._theme = this._theme === "light" ? "dark" : "light";
      this._toggleCount++;
      this._apply();
    }

    /** Register an observer callback(theme) */
    subscribe(fn) {
      this._observers.push(fn);
      // Immediately call with current theme so subscriber is in sync
      fn(this._theme);
      return () => {
        this._observers = this._observers.filter(o => o !== fn);
      };
    }

    // ── Private helpers ─────────────────────────────────────────────────────
    _apply() {
      document.documentElement.setAttribute("data-theme", this._theme);
      localStorage.setItem("theme", this._theme);
      this._notifyObservers();
    }

    _notifyObservers() {
      for (const fn of this._observers) {
        try { fn(this._theme); } catch (e) { console.error(e); }
      }
    }
  }

  // ══════════════════════════════════════════════════════════════════════════
  // Bootstrap — wire up all UI widgets to the singleton
  // ══════════════════════════════════════════════════════════════════════════
  (function init() {
    const manager = ThemeManager.getInstance();

    // ── Toggle button ────────────────────────────────────────────────────
    const toggleBtn = document.getElementById("themeToggleBtn");

    toggleBtn.addEventListener("click", () => {
      manager.toggle();
    });

    // ── Status widget ────────────────────────────────────────────────────
    const themeLabel    = document.getElementById("currentThemeLabel");
    const toggleCountEl = document.getElementById("toggleCount");
    const instanceCount = document.getElementById("instanceCount");

    // ── Toast ────────────────────────────────────────────────────────────
    const toast     = document.getElementById("toast");
    let   toastTimer = null;

    function showToast(theme) {
      toast.textContent =
        theme === "dark" ? "🌙 Dark mode activated" : "☀️ Light mode activated";
      toast.classList.add("show");
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => toast.classList.remove("show"), 2500);
    }

    // ── Subscribe to singleton ───────────────────────────────────────────
    let firstCall = true;
    manager.subscribe((theme) => {
      // Update toggle button ARIA
      toggleBtn.setAttribute(
        "aria-checked",
        theme === "dark" ? "true" : "false"
      );

      // Update status widget
      themeLabel.textContent    = theme;
      toggleCountEl.textContent = manager.toggleCount;
      instanceCount.textContent = "1 instance";   // always 1

      // Show toast (skip very first silent sync call)
      if (!firstCall) showToast(theme);
      firstCall = false;
    });

    // ── Demonstrate singleton guarantee in console ───────────────────────
    const a = ThemeManager.getInstance();
    const b = ThemeManager.getInstance();
    console.log(
      "%c[ThemeManager] Singleton guarantee: a === b →",
      "color:#818cf8; font-weight:bold;",
      a === b   // always true
    );

    // ── Demonstrate constructor guard in console ─────────────────────────
    try {
      const illegalInstance = new ThemeManager();
    } catch (err) {
      console.warn(
        "%c[ThemeManager] Constructor guard fired:",
        "color:#f87171; font-weight:bold;",
        err.message
      );
    }
  })();
</script>
</body>
</html>
