      --blockquote-border: #3b82f6;
    }

    [data-theme="dark"] {
      --bg-primary:    #0f172a;
      --bg-secondary:  #1e293b;
      --bg-card:       #1e293b;
      --bg-code:       #0f172a;
      --bg-tag:        #1e3a5f;
      --text-primary:  #f1f5f9;
      --text-secondary:#cbd5e1;
      --text-muted:    #94a3b8;
      --text-tag:      #93c5fd;
      --accent:        #60a5fa;
      --accent-hover:  #3b82f6;
      --accent-text:   #0f172a;
      --border:        #334155;
      --shadow:        rgba(0,0,0,0.4);
      --shadow-lg:     rgba(0,0,0,0.6);
      --pro-bg:        #052e16;
      --pro-border:    #166534;
      --pro-text:      #86efac;
      --con-bg:        #2d0a0a;
      --con-border:    #9f1239;
      --con-text:      #fda4af;
      --alt-bg:        #1c1a06;
      --alt-border:    #92400e;
      --alt-text:      #fcd34d;
      --toggle-bg:     #3b82f6;
      --toggle-knob:   #ffffff;
      --nav-bg:        #0f172a;
      --nav-text:      #f1f5f9;
      --hero-bg:       linear-gradient(135deg,#1e3a8a 0%,#4c1d95 100%);
      --hero-text:     #f1f5f9;
      --table-header:  #1e3a5f;
      --table-stripe:  #162032;
      --blockquote-bg: #1a2540;
      --blockquote-border: #60a5fa;
    }

    /* ── Reset & base ── */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      line-height: 1.7;
      transition: background var(--transition), color var(--transition);
      min-height: 100vh;
    }

    /* ── Navigation ── */
    nav {
      background: var(--nav-bg);
      color: var(--nav-text);
      padding: 0 2rem;
      display: flex;
      align-items: center;
      justify-content: space-between;
      height: 64px;
      position: sticky;
      top: 0;
      z-index: 100;
      box-shadow: 0 2px 12px var(--shadow-lg);
      transition: background var(--transition), box-shadow var(--transition);
    }

    .nav-brand {
      font-size: 1.25rem;
      font-weight: 700;
      letter-spacing: -0.5px;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }

    .nav-brand .badge {
      font-size: 0.65rem;
      background: var(--accent);
      color: var(--accent-text);
      padding: 2px 7px;
      border-radius: 20px;
      font-weight: 600;
      letter-spacing: 0.5px;
      text-transform: uppercase;
    }

    .nav-links {
      display: flex;
      gap: 1.5rem;
      list-style: none;
      align-items: center;
    }

    .nav-links a {
      color: rgba(255,255,255,0.8);
      text-decoration: none;
      font-size: 0.9rem;
      transition: color 0.2s;
    }

    .nav-links a:hover { color: #ffffff; }

    /* ── Theme toggle ── */
    .theme-toggle-wrap {
      display: flex;
      align-items: center;
      gap: 0.6rem;
    }

    .theme-label {
      font-size: 0.8rem;
      color: rgba(255,255,255,0.7);
      min-width: 36px;
    }

    .toggle-switch {
      position: relative;
      width: 52px;
      height: 28px;
      cursor: pointer;
    }

    .toggle-switch input { opacity: 0; width: 0; height: 0; }

    .toggle-track {
      position: absolute;
      inset: 0;
      background: var(--toggle-bg);
      border-radius: 28px;
      transition: background var(--transition);
    }

    .toggle-track::before {
      content: '';
      position: absolute;
      width: 22px;
      height: 22px;
      left: 3px;
      top: 3px;
      background: var(--toggle-knob);
      border-radius: 50%;
      transition: transform var(--transition);
      box-shadow: 0 1px 4px rgba(0,0,0,0.3);
    }

    .toggle-switch input:checked + .toggle-track::before {
      transform: translateX(24px);
    }

    /* ── Layout ── */
    .container {
      max-width: 1100px;
      margin: 0 auto;
      padding: 0 1.5rem;
    }

    section { padding: 3rem 0; }

    section + section {
      border-top: 1px solid var(--border);
    }

    h1 { font-size: clamp(2rem, 5vw, 3rem); line-height: 1.2; }
    h2 { font-size: 1.75rem; margin-bottom: 1rem; }
    h3 { font-size: 1.2rem; margin-bottom: 0.6rem; }

    p { color: var(--text-secondary); margin-bottom: 1rem; }
    p:last-child { margin-bottom: 0; }

    /* ── Hero ── */
    .hero {
      background: var(--hero-bg);
      color: var(--hero-text);
      padding: 5rem 1.5rem;
      text-align: center;
      transition: background var(--transition);
    }

    .hero h1 { color: var(--hero-text); margin-bottom: 1rem; }

    .hero p {
      color: rgba(255,255,255,0.85);
      font-size: 1.15rem;
      max-width: 600px;
      margin: 0 auto 2rem;
    }

    .hero-buttons {
      display: flex;
      gap: 1rem;
      justify-content: center;
      flex-wrap: wrap;
    }

    .btn {
      display: inline-block;
      padding: 0.65rem 1.5rem;
      border-radius: 8px;
      font-size: 0.95rem;
      font-weight: 600;
      cursor: pointer;
      text-decoration: none;
      border: none;
      transition: all 0.2s;
    }

    .btn-primary {
      background: var(--accent);
      color: var(--accent-text);
    }

    .btn-primary:hover {
      background: var(--accent-hover);
      transform: translateY(-1px);
      box-shadow: 0 4px 12px var(--shadow-lg);
    }

    .btn-outline {
      background: transparent;
      color: #ffffff;
      border: 2px solid rgba(255,255,255,0.6);
    }

    .btn-outline:hover {
      background: rgba(255,255,255,0.1);
      border-color: #ffffff;
    }

    /* ── Cards ── */
    .card-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 1.5rem;
    }

    .card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.5rem;
      box-shadow: 0 2px 8px var(--shadow);
      transition: background var(--transition), border var(--transition),
                  box-shadow var(--transition), transform 0.2s;
    }

    .card:hover {
      transform: translateY(-3px);
      box-shadow: 0 8px 24px var(--shadow-lg);
    }

    .card-icon {
      font-size: 2rem;
      margin-bottom: 0.75rem;
    }

    .card h3 { color: var(--text-primary); }
    .card p  { font-size: 0.92rem; }

    /* ── Code block ── */
    .code-wrap {
      background: var(--bg-code);
      border: 1px solid var(--border);
      border-radius: 10px;
      overflow: hidden;
      transition: background var(--transition), border var(--transition);
    }

    .code-header {
      background: var(--border);
      padding: 0.5rem 1rem;
      display: flex;
      align-items: center;
      gap: 0.5rem;
      font-size: 0.8rem;
      color: var(--text-muted);
      transition: background var(--transition);
    }

    .dot { width: 12px; height: 12px; border-radius: 50%; }
    .dot-red   { background: #ff5f57; }
    .dot-yellow{ background: #febc2e; }
    .dot-green { background: #28c840; }

    pre {
      padding: 1.25rem 1.5rem;
      overflow-x: auto;
      font-size: 0.85rem;
      line-height: 1.7;
    }

    code {
      font-family: 'Fira Code', 'Cascadia Code', Consolas, monospace;
      color: var(--text-primary);
    }

    .kw  { color: #a78bfa; }
    .fn  { color: #60a5fa; }
    .str { color: #34d399; }
    .cm  { color: var(--text-muted); font-style: italic; }
    .nm  { color: #f9a8d4; }

    /* ── Pros / Cons / Alternatives ── */
    .analysis-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 1.5rem;
      margin-top: 1.5rem;
    }

    .analysis-box {
      border-radius: 12px;
      padding: 1.5rem;
      border: 1px solid;
    }

    .pros-box {
      background: var(--pro-bg);
      border-color: var(--pro-border);
      transition: background var(--transition), border-color var(--transition);
    }

    .cons-box {
      background: var(--con-bg);
      border-color: var(--con-border);
      transition: background var(--transition), border-color var(--transition);
    }

    .alt-box {
      background: var(--alt-bg);
      border-color: var(--alt-border);
      transition: background var(--transition), border-color var(--transition);
    }

    .pros-box h3 { color: var(--pro-text); }
    .cons-box h3 { color: var(--con-text); }
    .alt-box  h3 { color: var(--alt-text); }

    .analysis-box ul {
      list-style: none;
      padding: 0;
      margin: 0;
    }

    .analysis-box li {
      padding: 0.45rem 0;
      font-size: 0.92rem;
      display: flex;
      gap: 0.5rem;
      border-bottom: 1px solid var(--border);
      transition: border-color var(--transition);
    }

    .analysis-box li:last-child { border-bottom: none; }

    .pros-box li { color: var(--pro-text); }
    .cons-box li { color: var(--con-text); }
    .alt-box  li { color: var(--alt-text); }

    /* ── Table ── */
    .table-wrap {
      overflow-x: auto;
      border-radius: 10px;
      border: 1px solid var(--border);
      transition: border-color var(--transition);
    }

    table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.92rem;
    }

    thead tr {
      background: var(--table-header);
      transition: background var(--transition);
    }

    th {
      padding: 0.85rem 1rem;
      text-align: left;
      font-weight: 600;
      color: var(--text-primary);
      border-bottom: 2px solid var(--border);
    }

    td {
      padding: 0.8rem 1rem;
      color: var(--text-secondary);
      border-bottom: 1px solid var(--border);
    }

    tr:last-child td { border-bottom: none; }

    tbody tr:nth-child(even) {
      background: var(--table-stripe);
      transition: background var(--transition);
    }

    tbody tr:hover { background: var(--bg-code); }

    /* ── Tags ── */
    .tag {
      display: inline-block;
      background: var(--bg-tag);
      color: var(--text-tag);
      border-radius: 20px;
      padding: 3px 12px;
      font-size: 0.78rem;
      font-weight: 600;
      margin: 0.2rem;
      transition: background var(--transition), color var(--transition);
    }

    /* ── Blockquote ── */
    blockquote {
      background: var(--blockquote-bg);
      border-left: 4px solid var(--blockquote-border);
      border-radius: 0 8px 8px 0;
      padding: 1rem 1.25rem;
      margin: 1.5rem 0;
      font-style: italic;
      color: var(--text-secondary);
      transition: background var(--transition), border-color var(--transition);
    }

    blockquote cite {
      display: block;
      margin-top: 0.5rem;
      font-size: 0.85rem;
      font-style: normal;
      font-weight: 600;
      color: var(--accent);
    }

    /* ── State display ── */
    .state-panel {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.5rem;
      display: flex;
      align-items: center;
      gap: 1.5rem;
      flex-wrap: wrap;
      transition: background var(--transition), border-color var(--transition);
    }

    .state-item {
      display: flex;
      flex-direction: column;
      gap: 0.25rem;
    }

    .state-label {
      font-size: 0.75rem;
      text-transform: uppercase;
      letter-spacing: 1px;
      color: var(--text-muted);
    }

    .state-value {
      font-size: 1rem;
      font-weight: 700;
      color: var(--accent);
      font-family: monospace;
    }

    .state-divider {
      width: 1px;
      height: 40px;
      background: var(--border);
    }

    /* ── Form elements ── */
    .form-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
      gap: 1rem;
    }

    .form-group { display: flex; flex-direction: column; gap: 0.4rem; }

    label {
      font-size: 0.85rem;
      font-weight: 600;
      color: var(--text-secondary);
    }

    input, select, textarea {
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 0.6rem 0.9rem;
      color: var(--text-primary);
      font-size: 0.9rem;
      font-family: inherit;
      transition: background var(--transition), border-color var(--transition),
                  color var(--transition);
      outline: none;
    }

    input:focus, select:focus, textarea:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(59,130,246,0.2);
    }

    textarea { resize: vertical; min-height: 80px; }

    /* ── Alert ── */
    .alert {
      padding: 1rem 1.25rem;
      border-radius: 8px;
      margin-bottom: 1rem;
      font-size: 0.92rem;
      display: flex;
      gap: 0.75rem;
      align-items: flex-start;
    }

    .alert-info {
      background: var(--blockquote-bg);
      border: 1px solid var(--blockquote-border);
      color: var(--text-secondary);
      transition: background var(--transition), border-color var(--transition);
    }

    /* ── Progress ── */
    .progress-list { display: flex; flex-direction: column; gap: 0.85rem; }

    .progress-item {}

    .progress-meta {
      display: flex;
      justify-content: space-between;
      font-size: 0.85rem;
      color: var(--text-secondary);
      margin-bottom: 0.35rem;
    }

    .progress-bar-bg {
      background: var(--border);
      border-radius: 99px;
      height: 8px;
      overflow: hidden;
      transition: background var(--transition);
    }

    .progress-bar-fill {
      height: 100%;
      border-radius: 99px;
      background: var(--accent);
      transition: background var(--transition);
    }

    /* ── Footer ── */
    footer {
      background: var(--nav-bg);
      color: rgba(255,255,255,0.7);
      text-align: center;
      padding: 2rem 1rem;
      font-size: 0.85rem;
      margin-top: 3rem;
      transition: background var(--transition);
    }

    footer a { color: var(--accent); text-decoration: none; }

    /* ── Responsive ── */
    @media (max-width: 640px) {
      .nav-links { display: none; }
      nav { padding: 0 1rem; }
      .hero { padding: 3rem 1rem; }
    }
  </style>
</head>
