      <span class="state-label">Toggle Count</span>
      <span class="state-value" id="toggleCount">0</span>
    </div>
    <div class="state-divider"></div>
    <div class="state-item">
      <span class="state-label">Listeners Registered</span>
      <span class="state-value" id="listenerCount">—</span>
    </div>
    <div class="state-divider"></div>
    <div class="state-item">
      <span class="state-label">Last Changed</span>
      <span class="state-value" id="lastChanged">—</span>
    </div>
  </div>

  <div class="alert alert-info" style="margin-top:1.5rem;">
    ℹ️ <span>
