<!-- ══════════════════════════════════════════
     CODE SECTION
══════════════════════════════════════════ -->
<section id="code">
  <h2>The Singleton Implementation</h2>
  <p>
    A private static <code>_instance</code> variable is the heart of the pattern.
    The constructor guards against multiple instantiation, and
    <code>getInstance()</code> is the single public entry point.
  </p>

  <div class="code-wrap">
    <div class="code-header">
      <span class="dot dot-red"></span>
      <span class="dot dot-yellow"></span>
      <span class="dot dot-green"></span>
      <span style="margin-left:0.5rem;">ThemeManager.js</span>
    </div>
    <pre><code><span class="kw">class</span> <span class="nm">ThemeManager</span> {
  <span class="cm">// ── Private static instance (the singleton slot) ──────────────</span>
  <span class="kw">static</span> <span class="nm">_instance</span> = <span class="kw">null</span>;

  <span class="cm">// ── Constructor is intentionally private-by-convention ────────</span>
  <span class="fn">constructor</span>() {
    <span class="kw">if</span> (<span class="nm">ThemeManager</span>.<span class="nm">_instance</span>) {
      <span class="cm">// Guard: return existing instance instead of creating new one</span>
      <span class="kw">return</span> <span class="nm">ThemeManager</span>.<span class="nm">_instance</span>;
    }

    <span class="cm">// First-time initialisation</span>
    <span class="kw">this</span>.<span class="nm">_theme</span>       = <span class="str">'light'</span>;
    <span class="kw">this</span>.<span class="nm">_toggleCount</span> = <span class="nm">0</span>;
    <span class="kw">this</span>.<span class="nm">_listeners</span>   = <span class="kw">new</span> <span class="fn">Set</span>();
    <span class="kw">this</span>.<span class="nm">_id</span>          = <span class="str">`tm_<span class="fn">${Date.now()}</span>`</span>;

    <span class="nm">ThemeManager</span>.<span class="nm">_instance</span> = <span class="kw">this</span>;
  }

  <span class="cm">// ── Public factory method ──────────────────────────────────────</span>
  <span class="kw">static</span> <span class="fn">getInstance</span>() {
    <span class="kw">if</span> (!<span class="nm">ThemeManager</span>.<span class="nm">_instance</span>) {
      <span class="kw">new</span> <span class="fn">ThemeManager</span>();
    }
    <span class="kw">return</span> <span class="nm">ThemeManager</span>.<span class="nm">_instance</span>;
  }

  <span class="cm">// ── Toggle between light and dark ─────────────────────────────</span>
  <span class="fn">toggle</span>() {
    <span class="kw">this</span>.<span class="nm">_theme</span> = <span class="kw">this</span>.<span class="nm">_theme</span> === <span class="str">'light'</span> ? <span class="str">'dark'</span> : <span class="str">'light'</span>;
    <span class="kw">this</span>.<span class="nm">_toggleCount</span>++;
    <span class="kw">this</span>.<span class="nm">_lastChanged</span> = <span class="kw">new</span> <span class="fn">Date</span>().<span class="fn">toLocaleTimeString</span>();
    <span class="kw">this</span>.<span class="fn">_apply</span>();
    <span class="kw">this</span>.<span class="fn">_notify</span>();
  }

  <span class="cm">// ── Apply theme to DOM ─────────────────────────────────────────</span>
  <span class="fn">_apply</span>() {
    document.<span class="nm">documentElement</span>.<span class="fn">setAttribute</span>(<span class="str">'data-theme'</span>, <span class="kw">this</span>.<span class="nm">_theme</span>);
  }

  <span class="cm">// ── Observer-style listener support ───────────────────────────</span>
  <span class="fn">subscribe</span>(<span class="nm">fn</span>) { <span class="kw">this</span>.<span class="nm">_listeners</span>.<span class="fn">add</span>(<span class="nm">fn</span>); }
  <span class="fn">unsubscribe</span>(<span class="nm">fn</span>) { <span class="kw">this</span>.<span class="nm">_listeners</span>.<span class="fn">delete</span>(<span class="nm">fn</span>); }
  <span class="fn">_notify</span>() { <span class="kw">this</span>.<span class="nm">_listeners</span>.<span class="fn">forEach</span>(<span class="nm">fn</span> => <span class="fn">fn</span>(<span class="kw">this</span>.<span class="nm">_theme</span>)); }

  <span class="cm">// ── Getters ────────────────────────────────────────────────────</span>
  <span class="kw">get</span> <span class="fn">theme</span>()        { <span class="kw">return</span> <span class="kw">this</span>.<span class="nm">_theme</span>; }
  <span class="kw">get</span> <span class="fn">toggleCount</span>() { <span class="kw">return</span> <span class="kw">this</span>.<span class="nm">_toggleCount</span>; }
  <span class="kw">get</span> <span class="fn">id</span>()           { <span class="kw">return</span> <span class="kw">this</span>.<span class="nm">_id</span>; }
  <span class="kw">get</span> <span class="fn">listenerCount</span>(){ <span class="kw">return</span> <span class="kw">this</span>.<span class="nm">_listeners</span>.<span class="nm">size</span>; }
  <span class="kw">get</span> <span class="fn">lastChanged</span>()  { <span class="kw">return</span> <span class="kw">this</span>.<span class="nm">_lastChanged</span> ?? <span class="str">'never'</span>; }
}</code></pre>
  </div>
</section>


<!-- ══════════════════════════════════════════
     PROS / CONS / ALTERNATIVES  (main focus)
══════════════════════════════════════════ -->
<section id="analysis">
  <h2>Singleton: Pros, Cons &amp; When to Reach for Alternatives</h2>
  <p>
    The Singleton pattern is one of the original Gang-of-Four patterns and
    arguably the most controversial. Understanding <em>why</em> it exists and
    <em>where it breaks down</em> is essential for writing maintainable software.
  </p>

  <div class="analysis-grid">

    <!-- PROS -->
    <div class="analysis-box pros-box">
      <h3>✅ Pros</h3>
      <ul>
        <li>✔ <strong>Single source of truth</strong> — all consumers share the same state; no accidental divergence.</li>
        <li>✔ <strong>Controlled instantiation</strong> — expensive resources (DB pools, config loaders) are created exactly once.</li>
        <li>✔ <strong>Global access point</strong> — any module can call <code>getInstance()</code> without prop-drilling or context boilerplate.</li>
        <li>✔ <strong>Lazy initialisation</strong> — the object is only created when first requested, not at app start-up.</li>
        <li>✔ <strong>Reduced memory footprint</strong> — one object vs. many duplicates for shared state.</li>
        <li>✔ <strong>Simple to reason about</strong> — for small apps the pattern is easy to understand and trace.</li>
      </ul>
    </div>

    <!-- CONS -->
    <div class="analysis-box cons-box">
      <h3>❌ Cons</h3>
      <ul>
        <li>✘ <strong>Hidden global state</strong> — any code can mutate it silently, making bugs hard to trace.</li>
        <li>✘ <strong>Tight coupling</strong> — callers depend on a concrete class, not an abstraction, making refactoring painful.</li>
        <li>✘ <strong>Difficult to unit-test</strong> — the instance persists between tests; you can't inject a mock without monkey-patching.</li>
        <li>✘ <strong>Violates SRP</strong> — the class manages both its own logic <em>and</em> its own lifecycle.</li>
        <li>✘ <strong>Concurrency issues</strong> — in multi-threaded environments (e.g. Node.js workers) double-instantiation can occur without locks.</li>
        <li>✘ <strong>Hides dependencies</strong> — it's not obvious from a function signature that it relies on the singleton.</li>
      </ul>
    </div>

    <!-- ALTERNATIVES -->
    <div class="analysis-box alt-box">
      <h3>🔄 When Alternatives Are Better</h3>
      <ul>
        <li>⚡ <strong>Dependency Injection (DI)</strong> — pass the shared object as a constructor/function argument. Dependencies are explicit, swappable, and testable.</li>
        <li>⚡ <strong>React Context / Provide-Inject</strong> — framework-native DI that scopes state to a component tree, avoiding true globals.</li>
        <li>⚡ <strong>Module-level exports</strong> — in ES modules, <code>export const store = new Store()</code> is effectively a singleton without the anti-pattern boilerplate.</li>
        <li>⚡ <strong>Service locator</strong> — a registry that resolves named services; still global but more flexible than a hard-coded class reference.</li>
        <li>⚡ <strong>Monostate pattern</strong> — multiple instances share the same static state; easier to mock than a true singleton.</li>
        <li>⚡ <strong>Zustand / Redux / Signals</strong> — purpose-built state management with time-travel, devtools, and proper scoping.</li>
      </ul>
    </div>
  </div>

  <blockquote>
    "The Singleton pattern is justified when you genuinely need one — and only one —
    instance of a class. The moment you need a second instance in tests, or a
    different instance per environment, reach for Dependency Injection instead."
    <cite>— Paraphrased from <em>Clean Code</em>, Robert C. Martin</cite>
  </blockquote>

  <!-- Comparison table -->
  <h3 style="margin-top:2rem; margin-bottom:0.75rem;">Pattern Comparison at a Glance</h3>
  <div class="table-wrap">
    <table>
      <thead>
        <tr>
          <th>Criterion</th>
          <th>Singleton</th>
          <th>Dependency Injection</th>
          <th>Module Export</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td>Single instance guarantee</td>
          <td>✅ Enforced</td>
          <td>⚠️ Convention</td>
          <td>✅ By module system</td>
        </tr>
        <tr>
          <td>Testability</td>
          <td>❌ Hard to mock</td>
          <td>✅ Inject mock easily</td>
          <td>⚠️ Requires jest.mock()</td>
        </tr>
        <tr>
          <td>Explicit dependencies</td>
          <td>❌ Hidden</td>
          <td>✅ Visible in signature</td>
          <td>⚠️ Import is visible</td>
        </tr>
        <tr>
          <td>Boilerplate</td>
          <td>⚠️ Medium</td>
          <td>⚠️ Medium–High</td>
          <td>✅ Minimal</td>
        </tr>
        <tr>
          <td>Framework agnostic</td>
          <td>✅ Yes</td>
          <td>✅ Yes</td>
          <td>✅ Yes (ESM)</td>
        </tr>
        <tr>
          <td>Best for</td>
          <td>Config, loggers, caches</td>
          <td>Services, repositories</td>
          <td>Simple shared state</td>
        </tr>
      </tbody>
    </table>
  </div>
</section>


