  <!-- ── Singleton Pattern Section ── -->
  <section id="pattern">
    <div class="container">
      <h4>Core Concept</h4>
      <h2>How the Singleton Works Here</h2>
      <p>The <code>ThemeManager</code> class below is the single source of truth for theme state. No matter how many times you call <code>ThemeManager.getInstance()</code>, you always get the exact same object — proven by reference equality.</p>

      <div class="singleton-diagram">
        <h3>Instance Lifecycle</h3>
        <div class="diagram-row">
          <div class="diagram-box">Component A<br/><small>calls getInstance()</small></div>
          <div class="diagram-arrow">→</div>
          <div class="diagram-box instance">🔒 Single Instance<br/><small>ThemeManager._instance</small></div>
          <div class="diagram-arrow">←</div>
          <div class="diagram-box">Component B<br/><small>calls getInstance()</small></div>
        </div>
        <div class="diagram-row" style="margin-top:0.75rem">
          <div class="diagram-box">Nav Toggle</div>
          <div class="diagram-arrow">→</div>
          <div class="diagram-box instance">Same Object ✓</div>
          <div class="diagram-arrow">←</div>
          <div class="diagram-box">Hero Button</div>
        </div>
        <p style="text-align:center; margin-top:1rem; font-size:0.85rem; color:var(--text-muted)">All callers share one instance — <code>instanceA === instanceB</code> is always <strong>true</strong></p>
      </div>

      <pre><code><span class="code-comment">// ── Singleton ThemeManager ──────────────────────────</span>
<span class="code-keyword">class</span> <span class="code-fn">ThemeManager</span> {
  <span class="code-keyword">static</span> <span class="code-var">_instance</span> = <span class="code-keyword">null</span>;   <span class="code-comment">// the one and only instance</span>

  <span class="code-fn">constructor</span>() {
    <span class="code-keyword">if</span> (ThemeManager._instance) {
      <span class="code-keyword">return</span> ThemeManager._instance;  <span class="code-comment">// guard: return existing</span>
    }
    <span class="code-keyword">this</span>.<span class="code-var">_theme</span>        = <span class="code-string">'light'</span>;
    <span class="code-keyword">this</span>.<span class="code-var">_toggleCount</span>  = <span class="code-var">0</span>;
    <span class="code-keyword">this</span>.<span class="code-var">_subscribers</span>  = [];
    ThemeManager._instance = <span class="code-keyword">this</span>;
  }

  <span class="code-comment">/** Always returns the same object */</span>
  <span class="code-keyword">static</span> <span class="code-fn">getInstance</span>() {
    <span class="code-keyword">if</span> (!ThemeManager._instance) {
      <span class="code-keyword">new</span> <span class="code-fn">ThemeManager</span>();
    }
    <span class="code-keyword">return</span> ThemeManager._instance;
  }

  <span class="code-fn">toggle</span>() {
    <span class="code-keyword">this</span>._theme = <span class="code-keyword">this</span>._theme === <span class="code-string">'light'</span> ? <span class="code-string">'dark'</span> : <span class="code-string">'light'</span>;
    <span class="code-keyword">this</span>._toggleCount++;
    <span class="code-keyword">this</span>.<span class="code-fn">_apply</span>();
    <span class="code-keyword">this</span>.<span class="code-fn">_notify</span>();
  }

  <span class="code-fn">subscribe</span>(<span class="code-var">fn</span>) { <span class="code-keyword">this</span>._subscribers.<span class="code-fn">push</span>(fn); }

  <span class="code-fn">_apply</span>() {
    document.body.<span class="code-fn">setAttribute</span>(<span class="code-string">'data-theme'</span>, <span class="code-keyword">this</span>._theme);
  }

  <span class="code-fn">_notify</span>() {
    <span class="code-keyword">this</span>._subscribers.<span class="code-fn">forEach</span>(<span class="code-var">fn</span> => <span class="code-fn">fn</span>(<span class="code-keyword">this</span>._theme));
  }
}

<span class="code-comment">// Usage — same instance every time:</span>
<span class="code-keyword">const</span> <span class="code-var">a</span> = ThemeManager.<span class="code-fn">getInstance</span>();
<span class="code-keyword">const</span> <span class="code-var">b</span> = ThemeManager.<span class="code-fn">getInstance</span>();
console.<span class="code-fn">log</span>(a === b); <span class="code-comment">// → true ✓</span></code></pre>
    </div>
  </section>

