  <script>
    /* ═══════════════════════════════════════════════════════════
       SINGLETON THEME MANAGER
       ═══════════════════════════════════════════════════════════ */
    class ThemeManager {
      static _instance = null;

      constructor() {
        // Guard: if an instance already exists, return it
        if (ThemeManager._instance) {
          return ThemeManager._instance;
        }
        this._theme        = 'light';
        this._toggleCount  = 0;
        this._subscribers  = [];
        this._instanceId   = Math.random().toString(36).slice(2, 8).toUpperCase();
        ThemeManager._instance = this;
      }

      /** The one public entry point — always returns the same object */
      static getInstance() {
        if (!ThemeManager._instance) {
          new ThemeManager();
        }
        return ThemeManager._instance;
      }

      get theme()       { return this._theme; }
      get toggleCount() { return this._toggleCount; }
      get instanceId()  { return this._instanceId; }
      get subscriberCount() { return this._subscribers.length; }

      toggle() {
        this._theme = this._theme === 'light' ? 'dark' : 'light';
        this._toggleCount++;
        this._apply();
        this._notify();
      }

      setTheme(t) {
        if (t !== this._theme) {
          this._theme = t;
          this._toggleCount++;
          this._apply();
          this._notify();
        }
      }

      subscribe(fn) {
        this._subscribers.push(fn);
        return () => {                          // returns unsubscribe fn
          this._subscribers = this._subscribers.filter(s => s !== fn);
        };
      }

      _apply() {
        document.body.setAttribute('data-theme', this._theme);
        // Update toggle button ARIA
        const btn = document.getElementById('themeToggle');
        if (btn) btn.setAttribute('aria-checked', this._theme === 'dark');
      }

      _notify() {
        this._subscribers.forEach(fn => fn(this._theme, this._toggleCount));
      }
    }

    /* ═══════════════════════════════════════════════════════════
       BOOT — create the singleton on page load
       ═══════════════════════════════════════════════════════════ */
    const tm = ThemeManager.getInstance();

    /* ── Subscribe: update all reactive UI ── */
    tm.subscribe((theme, count) => {
      // Hero emoji
      const emoji = document.getElementById('heroEmoji');
      if (emoji) emoji.textContent = theme === 'dark' ? '🌙' : '☀️';

      // Status bar
      const st = document.getElementById('statusTheme');
      if (st) st.textContent =
        `Current theme: ${theme === 'dark' ? 'Dark 🌙' : 'Light ☀️'} | Toggle count: ${count}`;

      // Stat cards
      document.getElementById('statToggles').textContent = count;
      document.getElementById('statCurrent').textContent = theme === 'dark' ? '🌙' : '☀️';

      // Footer
      document.getElementById('footerToggles').textContent = count;

      // Alert subscriber count
      const sc = document.getElementById('subCount');
      if (sc) sc.textContent = tm.subscriberCount;
    });

    /* Count this subscriber */
    document.getElementById('statSubscribers').textContent = tm.subscriberCount;
    document.getElementById('subCount').textContent = tm.subscriberCount;

    /* ── Wire the nav toggle button ── */
    document.getElementById('themeToggle').addEventListener('click', () => {
      tm.toggle();
    });

    /* ═══════════════════════════════════════════════════════════
       SINGLETON DEMO — prove reference equality
       ═══════════════════════════════════════════════════════════ */
    function runSingletonDemo() {
      const log = document.getElementById('instanceLog');
      const refs = [];

      log.innerHTML = '<div class="log-line log-info">// Requesting 5 instances from ThemeManager.getInstance()...</div>';

      for (let i = 1; i <= 5; i++) {
        const inst = ThemeManager.getInstance();
        refs.push(inst);

        const same = i > 1 ? refs[0] === inst : null;
        const line = document.createElement('div');
        line.className = 'log-line' + (same === true ? ' log-same' : '');
        line.textContent = same === null
          ? `  const ref${i} = ThemeManager.getInstance();  // → id: "${inst.instanceId}" (first instance created)`
          : `  const ref${i} = ThemeManager.getInstance();  // → id: "${inst.instanceId}"  ref${i} === ref1: ${same} ✓`;
        log.appendChild(line);
      }

      const allSame = refs.every(r => r === refs[0]);
      const summary = document.createElement('div');
      summary.className = 'log-line log-same';
      summary.textContent = `\n  // All 5 references identical? → ${allSame}  ✓ Singleton confirmed.`;
      log.appendChild(summary);

      log.scrollTop = log.scrollHeight;
    }

    function clearLog() {
      document.getElementById('instanceLog').innerHTML =
        '<div class="log-line log-info">// Log cleared. Click "Request 5 Instances" to run again.</div>';
    }
  </script>
</body>
</html>
```

## What this file demonstrates

### Singleton implementation
- `ThemeManager._instance` is the static slot that holds the one object
- The constructor returns the existing instance if called again
- `getInstance()` is the only public entry point — callers never use `new` directly
- Reference equality (`ref1 === ref5`) is proven live in the interactive demo

### Theme switching mechanics
- The singleton writes a single `data-theme` attribute on `<body>`
- Every colour, background, border, and shadow is a **CSS custom property** that reacts to that attribute — no per-element JS needed
- A built-in **Observer** (`subscribe`) notifies all registered listeners simultaneously

### Pros/Cons section
Covers all major trade-offs: global mutable state, hidden dependencies, poor testability, and when the pattern is genuinely appropriate

### Alternatives section
Explains Constructor Injection, React Context, Zustand/Redux, and IoC containers with code examples and a comparison table showing testability, explicitness, and complexity trade-offs

