&nbsp;&nbsp;}<br>
&nbsp;&nbsp;<span class="code-keyword">static</span> <span class="code-fn">getInstance</span>() {<br>
&nbsp;&nbsp;&nbsp;&nbsp;<span class="code-comment">// Same object. Every. Time.</span><br>
&nbsp;&nbsp;&nbsp;&nbsp;<span class="code-keyword">return</span> ThemeManager.#instance<br>
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;?? (ThemeManager.#instance =<br>
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class="code-keyword">new</span> <span class="code-fn">ThemeManager</span>());<br>
&nbsp;&nbsp;}<br>
}
