<script>
  /* ═══════════════════════════════════════════════
     THE SINGLETON
     Classic implementation with instance guard,
     observer list, and deliberate instrumentation
     so you can watch it work (and see its limits).
  ═══════════════════════════════════════════════ */
  class ThemeManager {
    constructor() {
      if (ThemeManager._instance) {
        // This is the guard. In practice callers never
        // see this throw because getInstance() shields them.
        // That invisibility is part of the problem.
        throw new Error(
          'ThemeManager is a singleton. Use ThemeManager.getInstance().'
        );
      }
      this._theme       = 'light';
      this._toggleCount = 0;
      this._subscribers = new Map(); // name → callback
      this._instanceId  = Math.random().toString(36).slice(2, 8);
      log(`Singleton created · id=${this._instanceId}`);
    }

    static getInstance() {
      if (!ThemeManager._instance) {
        ThemeManager._instance = new ThemeManager();
      }
      return ThemeManager._instance;
    }

    get theme()       { return this._theme; }
    get toggleCount() { return this._toggleCount; }
    get instanceId()  { return this._instanceId; }

    subscribe(name, callback) {
      this._subscribers.set(name, callback);
      log(`Subscriber registered: ${name}`);
      updateInspector();
      renderSubscriberList();
    }

    unsubscribe(name) {
      this._subscribers.delete(name);
      log(`Subscriber removed: ${name}`);
      updateInspector();
      renderSubscriberList();
    }

    toggle() {
      this._theme = this._theme === 'light' ? 'dark' : 'light';
      this._toggleCount++;
      log(`Theme → ${this._theme} (toggle #${this._toggleCount})`);
      this._notify();
    }

    _notify() {
      this._subscribers.forEach((cb, name) => {
        log(`  notifying: ${name}`);
        cb(this._theme);
      });
      // Apply to DOM
      document.body.className = this._theme;
      updateInspector();
      updateToggleButton();
    }
  }

