<script>
  // ─────────────────────────────────────────────
  //  THE SINGLETON
  //  Private field (#instance) prevents external
  //  instantiation. getInstance() is the only door.
  // ─────────────────────────────────────────────
  class ThemeManager {
    static #instance = null;

    constructor() {
      if (ThemeManager.#instance) {
        throw new Error("Use ThemeManager.getInstance().");
      }
      this.theme       = 'light';
      this.toggleCount = 0;
      this.subscribers = [];
    }

    static getInstance() {
      if (!ThemeManager.#instance) {
        ThemeManager.#instance = new ThemeManager();
      }
      return ThemeManager.#instance;
    }

    toggle() {
      this.theme = this.theme === 'light' ? 'dark' : 'light';
      this.toggleCount++;
      this._notify();
    }

    subscribe(fn) {
      this.subscribers.push(fn);
    }

    _notify() {
      this.subscribers.forEach(fn => fn(this.theme, this.toggleCount));
    }
  }

  // ─────────────────────────────────────────────
  //  WIRE UP THE UI
  //  Subscribe once. All elements react to the
  //  single shared instance — for better or worse.
  // ─────────────────────────────────────────────
  ThemeManager.getInstance().subscribe((theme, count) => {
    // Apply theme to body
    document.body.className = theme;

    // Update status bar
    document.getElementById('themeLabel').textContent =
      theme.charAt(0).toUpperCase() + theme.slice(1);
    document.getElementById('toggleCount').textContent = count;

    // Update both toggle buttons
    const isDark = theme === 'dark';
    document.getElementById('navToggle').textContent  = isDark ? '☀️ Light Mode' : '🌙 Dark Mode';
    document.getElementById('cardToggle').textContent = isDark ? '☀️ Light'      : '🌙 Dark';
  });
</script>
